
(function(){
  'use strict';
  const VERSION='V63.15';
  const SUPABASE_URL='https://uibhpgcsgcievktxmcfg.supabase.co';
  const LESSONS={"fa":[{"order":1,"code":"class_01_new_creature","classTitle":"کلاس ۱: خلقت تازه","title":"خلقت تازه: هویت تازه در مسیح","text":"هدف درس\nدر این درس، دانشجو باید بفهمد که ایمان به عیسی مسیح فقط یک تغییر اخلاقی یا مذهبی نیست؛ بلکه تولد تازه و آغاز یک زندگی کاملاً تازه است. اصطلاح «خلقت تازه» از ۲ قرنتیان ۵:۱۷ گرفته شده است: «اگر کسی در مسیح باشد، خلقت تازه‌ای است؛ چیزهای کهنه درگذشت، اینک همه چیز تازه شده است.» این حقیقت پایه‌ای، نقطه شروع زندگی مسیحی است.\n\n۱. خلقت تازه یعنی چه؟\nخلقت تازه یعنی انسانی که در مسیح دوباره متولد شده است. او همان شخص قبلی با کمی اصلاح اخلاقی نیست؛ او در روح خود حیاتی تازه از خدا دریافت کرده است. وقتی شخص عیسی مسیح را به عنوان خداوند و نجات‌دهنده شخصی خود می‌پذیرد، وارد یک طبقه تازه از زندگی می‌شود. گذشته او دیگر هویت او نیست. شکست‌ها، گناه، ترس، محکومیت، شرمندگی و سلطه تاریکی دیگر نباید او را تعریف کنند.\n\nدر یوحنا ۳:۱۶، عیسی اعلام می‌کند که هر که به او ایمان آورد هلاک نگردد بلکه حیات جاودانی داشته باشد. این آیه فقط وعده رفتن به آسمان نیست؛ اعلام انتقال از قلمرو هلاکت به قلمرو حیات است. کسی که به مسیح ایمان آورده، از دسته کسانی که باید هلاک شوند جدا شده است. کولسیان ۱:۱۳ می‌گوید خدا ما را از قدرت تاریکی رهانیده و به پادشاهی پسر محبت خود منتقل کرده است. بنابراین ایماندار نباید خود را قربانی، شکست‌خورده یا اسیر گذشته بداند.\n\n۲. سه چیز بزرگ که دریافت کرده‌ایم\nوقتی عیسی را پذیرفتید، چند حقیقت بزرگ در زندگی شما اتفاق افتاد:\n\nاول، حیات جاودانی دریافت کردید. اول یوحنا ۵:۱۱-۱۲ می‌گوید خدا حیات جاودانی به ما داده و این حیات در پسر اوست. حیات جاودانی فقط طول عمر بی‌پایان نیست؛ کیفیت زندگی خداست که به روح انسان داده می‌شود.\n\nدوم، عدالت خدا را دریافت کردید. رومیان ۵:۱۸-۱۹ نشان می‌دهد که همان‌گونه که نافرمانی یک انسان اثر گذاشت، اطاعت مسیح نیز ما را وارد جایگاه عدالت کرد. عدالت یعنی انسان بتواند بدون ترس، محکومیت یا احساس بی‌لیاقتی در حضور خدا بایستد.\n\nسوم، مشارکت با خدا را دریافت کردید. اول یوحنا ۱:۳ و یوحنا ۱۷:۲۱ نشان می‌دهد که هدف نهایی خدا فقط بخشیدن گناه نبود، بلکه آوردن انسان به مشارکت با خودش بود. این یعنی اکنون می‌توانید با خدا زندگی کنید، او را بشناسید، صدای او را از طریق کلام و روح بشنوید و در حضور او رشد کنید.\n\n۳. نجات شما بر اساس فیض است، نه اعمال\nافسسیان ۲:۸-۹ می‌گوید: «به فیض نجات یافته‌اید، به وسیله ایمان، و این از شما نیست، بلکه بخشش خداست؛ نه از اعمال تا هیچ‌کس فخر نکند.» این آیه بسیار مهم است. هیچ انسانی شما را واجد شرایط نجات نکرده است و هیچ انسانی نمی‌تواند شما را از نجاتی که خدا داده محروم کند. شما نجات را با ایمان و اعتراف دریافت کردید، همان‌طور که رومیان ۱۰:۹-۱۰ تعلیم می‌دهد: ایمان در قلب و اعتراف با دهان.\n\nاین بدان معنا نیست که اعمال مهم نیستند؛ بلکه اعمال خوب نتیجه حیات تازه‌اند، نه علت نجات. شما برای نجات یافتن کار خوب انجام نمی‌دهید؛ چون نجات یافته‌اید، توانایی زندگی درست و کارهای خوب را دریافت می‌کنید.\n\n۴. اطمینان نجات بر احساسات بنا نمی‌شود\nگاهی شخص ممکن است بگوید: «امروز احساس نمی‌کنم نجات یافته‌ام.» اما احساسات معیار حقیقت نیستند. دو شاهد اصلی برای اطمینان نجات وجود دارد: کلام خدا و شهادت روح‌القدس در قلب ما. رومیان ۸:۱۶ می‌گوید روح خدا با روح ما شهادت می‌دهد که فرزندان خدا هستیم. بنابراین وقتی احساسات تغییر می‌کنند، حقیقت تغییر نمی‌کند. مثل اینکه حتی اگر کسی احساس نکند مغزش کار می‌کند، حقیقت این است که مغزش کار می‌کند. به همین شکل، نجات بر احساس لحظه‌ای بنا نشده، بلکه بر کلام خدا و کار کامل مسیح بنا شده است.\n\n۵. انسان روح است، جان دارد و در بدن زندگی می‌کند\nاول تسالونیکیان ۵:۲۳ نشان می‌دهد که انسان روح، جان و بدن دارد. وقتی تولد تازه می‌یابید، حیات خدا در روح شما قرار می‌گیرد. اما ذهن شما باید با کلام خدا تازه شود. رومیان ۱۲:۲ می‌گوید با تازه شدن ذهن خود دگرگون شوید. یعنی باید یاد بگیرید همان‌طور فکر کنید که خدا درباره شما فکر می‌کند. اگر ذهن انسان هنوز با ترس، شکست، گذشته و محکومیت پر باشد، ممکن است با وجود داشتن حیات تازه، زندگی بیرونی او هنوز مطابق حقیقت تازه‌اش نباشد. کلام خدا ذهن را تازه می‌کند و زندگی را دگرگون می‌سازد.\n\n۶. خلقت تازه چه جایگاهی دارد؟\nبر اساس کلام خدا، خلقت تازه در مسیح کامل است. کولسیان ۲:۹-۱۰ می‌گوید شما در او کامل هستید. او در پادشاهی خدا قرار گرفته است. او با مسیح در جایگاه قدرت نشانده شده است، همان‌طور که افسسیان ۲:۶ می‌گوید. او حامل حضور خداست، زیرا اول قرنتیان ۶:۱۹ می‌گوید بدن شما معبد روح‌القدس است. او از بذر فاسدشدنی تولد نیافته، بلکه از کلام زنده و پایدار خدا، همان‌طور که اول پطرس ۱:۲۳ تعلیم می‌دهد.\n\nمثال عملی\nفرض کنید شخصی از کشوری به کشور دیگری مهاجرت کند و تابعیت جدید بگیرد. او دیگر با قوانین کشور قبلی زندگی نمی‌کند، بلکه به نظام جدید تعلق دارد. تولد تازه بسیار عمیق‌تر از این است؛ شما فقط آدرس عوض نکرده‌اید، بلکه به پادشاهی خدا منتقل شده‌اید. بنابراین باید یاد بگیرید با هویت و حقوق پادشاهی جدید خود زندگی کنید.\n\nجمع‌بندی\nشما در مسیح یک خلقت تازه هستید. گذشته شما قدرت نهایی بر شما ندارد. نجات شما به فیض است. شما حیات جاودانی، عدالت و مشارکت با خدا را دریافت کرده‌اید. اکنون باید ذهن خود را با کلام خدا تازه کنید و مطابق حقیقت تازه‌ای که در مسیح دارید زندگی کنید.","keyScriptures":"۲ قرنتیان ۵:۱۷-۱۸؛ یوحنا ۳:۱۶؛ رومیان ۱۰:۹-۱۱؛ افسسیان ۲:۸-۱۰؛ رومیان ۵:۱۷؛ اول یوحنا ۵:۱۱-۱۳؛ رومیان ۸:۱۶؛ اول تسالونیکیان ۵:۲۳؛ رومیان ۱۲:۲؛ کولسیان ۳:۱۰؛ اول پطرس ۲:۹؛ دوم پطرس ۱:۳؛ کولسیان ۱:۱۳؛ افسسیان ۲:۶؛ اول قرنتیان ۶:۱۹؛ اول پطرس ۱:۲۳","assignment":"با استفاده از زندگی خودتان توضیح دهید که «اگر کسی در مسیح باشد، خلقت تازه است» برای شما چه معنی دارد. سپس بنویسید آیا با وجود احساسات، شرایط یا گذشته خود، همچنان از نجات خود مطمئن هستید و چرا.","audioFile":"class-01-fa.mp3"},{"order":2,"code":"class_02_holy_spirit","classTitle":"کلاس ۲: روح‌القدس","title":"روح‌القدس: حضور، قدرت و مشارکت خدا در زندگی ایماندار","text":"هدف درس\nهدف این درس این است که دانشجو روح‌القدس را به عنوان شخص الهی، حضور فعال خدا و نیروی ضروری زندگی مسیحی بشناسد. زندگی مسیحی بدون روح‌القدس فقط تلاش انسانی می‌شود؛ اما با روح‌القدس، ایماندار توانایی زندگی پیروزمندانه، شهادت مؤثر، دعا، پرستش و خدمت را دریافت می‌کند.\n\n۱. روح‌القدس اختیاری نیست\nعیسی در لوقا ۲۴:۴۹ به شاگردان فرمود که منتظر بمانند تا از اعلی به قوت آراسته شوند. در اعمال ۱:۸ نیز فرمود: «چون روح‌القدس بر شما آید، قوت خواهید یافت و شاهدان من خواهید بود.» این نشان می‌دهد که خدمت و زندگی مسیحی از قدرت روح آغاز می‌شود، نه از توانایی انسانی. شاگردان با اینکه عیسی را دیده بودند و سخنان او را شنیده بودند، هنوز نیاز داشتند با روح‌القدس توانمند شوند.\n\n۲. روح‌القدس کیست؟\nروح‌القدس یک احساس، انرژی یا فضای مذهبی نیست؛ او خود خداست. او با پدر و پسر هم‌ذات و هم‌مرتبه است. عیسی در یوحنا ۱۵:۲۶ او را «تسلی‌دهنده» و «روح راستی» معرفی کرد که از پدر صادر می‌شود و درباره مسیح شهادت می‌دهد. نخستین اشاره به روح خدا در پیدایش ۱:۲ دیده می‌شود، جایی که روح خدا بر روی آب‌ها حرکت می‌کرد. این نشان می‌دهد که روح‌القدس انجام‌دهنده قصدهای خداست.\n\nروح‌القدس حضور خدا را برای ما واقعی می‌کند. افسسیان ۲:۲۲ می‌گوید ما به واسطه روح، مسکن خدا می‌شویم. او شخصیت دارد؛ می‌تواند سخن بگوید، همان‌طور که در اعمال ۱۳:۲ روح‌القدس گفت؛ و می‌تواند محزون شود، همان‌طور که افسسیان ۴:۳۰ هشدار می‌دهد. بنابراین رابطه با روح‌القدس یک رابطه واقعی است، نه یک مفهوم نظری.\n\n۳. تعمید روح‌القدس و دریافت روح‌القدس\nطبق اول قرنتیان ۱۲:۱۳، روح‌القدس ایماندار را هنگام تولد تازه در بدن مسیح قرار می‌دهد. این کار روح در نجات است. اما ایماندار همچنین باید روح‌القدس را به عنوان ساکن در خود دریافت کند و با او مشارکت داشته باشد. این تجربه می‌تواند هم‌زمان با تولد تازه اتفاق بیفتد، اما از نظر تعلیم، باید فهمیده شود که زندگی مسیحی نیازمند سکونت و عمل روح‌القدس در شخص است.\n\n۴. خدمت اصلی روح‌القدس در زندگی مسیحی\nاعمال ۱:۸ روشن می‌کند که وقتی روح‌القدس بر ایماندار می‌آید، او قدرت می‌یابد تا زندگی مسیحی را با موفقیت زندگی کند و شاهد عیسی باشد. این قدرت فقط برای احساس روحانی نیست؛ برای زیستن، شهادت دادن، خدمت، دعا، محبت، پاکی، رشد و ثبات است. روح‌القدس تسلی‌دهنده، مشاور، مددکار، شفیع، مدافع، قوت‌دهنده و همراه ایماندار است.\n\n۵. چگونه روح‌القدس را دریافت کنیم؟\nاعمال ۲:۱۷ و غلاطیان ۳:۱۴ نشان می‌دهد که وعده روح برای ایمانداران است. کسی که انجیل را پذیرفته، می‌تواند با ایمان روح‌القدس را دریافت کند. شخص می‌تواند با احترام و ایمان بگوید: «در نام عیسی مسیح، قلب خود را باز می‌کنم و روح‌القدس را دریافت می‌کنم.» همان‌طور که نجات را با ایمان دریافت کردید، روح‌القدس را نیز با ایمان دریافت می‌کنید. در اعمال ۱۹:۶ نیز می‌بینیم که با دست‌گذاری، ایمانداران روح‌القدس را دریافت کردند و به زبان‌ها سخن گفتند.\n\n۶. سخن گفتن به زبان‌ها\nمرقس ۱۶:۱۷ نشان می‌دهد که یکی از نشانه‌های ایمانداران، سخن گفتن به زبان‌های تازه است. زبان‌ها هدیه‌ای برای بنا شدن، دعا و پرستش هستند. یهودا ۱:۲۰ می‌گوید با دعا در روح‌القدس خود را در ایمان مقدس بنا کنید. اول قرنتیان ۱۴:۲ می‌گوید کسی که به زبان‌ها سخن می‌گوید، با خدا سخن می‌گوید و اسرار را بیان می‌کند. اعمال ۱۰:۴۶ نیز نشان می‌دهد که زبان‌ها می‌تواند برای جلال دادن خدا باشد. وقتی به زبان‌ها دعا می‌کنید، محدودیت زبان طبیعی کنار می‌رود و روح شما با خدا ارتباط می‌گیرد.\n\n۷. هفت جلوه روح خدا\nاشعیا ۱۱:۲ از روح خدا با ابعاد گوناگون سخن می‌گوید: روح خداوند، روح حکمت، روح فهم، روح مشورت، روح قوت، روح معرفت و روح ترس خداوند. این به معنای وجود هفت روح جداگانه نیست، بلکه نشان‌دهنده ابعاد کامل عمل روح‌القدس است. ایماندار باید بداند که وقتی روح‌القدس را دارد، با شخصی کامل، قدرتمند و حکیم در مشارکت است.\n\n۸. ثمره روح و عطایای خدمت\nغلاطیان ۵:۲۲-۲۳ ثمرات روح را معرفی می‌کند: محبت، شادی، سلامتی، حلم، مهربانی، نیکویی، ایمان، فروتنی و خویشتنداری. این ثمرات باید در زندگی ایماندار ظاهر شوند، زیرا طبیعت تازه در اوست. همچنین افسسیان ۴:۱۱ از عطایای خدمتی سخن می‌گوید: رسول، نبی، مبشر، شبان و معلم. این خدمات برای تجهیز مقدسین و بنای بدن مسیح داده شده‌اند.\n\nمثال عملی\nیک تلفن همراه بدون شارژ ممکن است زیبا و گران باشد، اما کارایی ندارد. ایماندار بدون مشارکت فعال با روح‌القدس نیز می‌تواند اطلاعات داشته باشد، اما قدرت عملی زندگی مسیحی را تجربه نکند. روح‌القدس قدرت درونی، هدایت، روشنایی و توانایی خدا در زندگی شماست.\n\nجمع‌بندی\nروح‌القدس برای زندگی مسیحی ضروری است. او خداست، در شما ساکن می‌شود، شما را توانمند می‌کند، شما را بنا می‌کند، شما را هدایت می‌کند و شما را شاهد مؤثر عیسی می‌سازد. با او مشارکت کنید، با او سخن بگویید، به زبان‌ها دعا کنید و اجازه دهید شخصیت او از طریق شما ظاهر شود.","keyScriptures":"یوحنا ۱۴:۱۶-۲۰؛ اعمال ۱:۸؛ لوقا ۲۴:۴۹؛ اعمال ۲:۱-۴؛ اول قرنتیان ۱۲:۱۳؛ یوحنا ۱۵:۲۶؛ پیدایش ۱:۲؛ اشعیا ۶۳:۹-۱۰؛ افسسیان ۲:۲۲؛ یوحنا ۱۴:۱۷ و ۲۶؛ افسسیان ۴:۳۰؛ اعمال ۱۳:۲؛ یوحنا ۱۶:۸؛ یوئیل ۲:۲۸؛ اعمال ۲:۱۷؛ اعمال ۵:۳۲؛ غلاطیان ۳:۱۴؛ اعمال ۱۹:۶؛ مرقس ۱۶:۱۷؛ یهودا ۱:۲۰؛ اول قرنتیان ۱۴:۲ و ۱۵؛ اعمال ۱۰:۴۶؛ اشعیا ۱۱:۲؛ غلاطیان ۵:۲۲-۲۳؛ افسسیان ۴:۱۱-۱۲","assignment":"هر روز تا درس بعدی حداقل ۱۰ دقیقه به زبان‌ها دعا کنید و بنویسید چه افکار، قوت، آرامش، هدایت یا تغییراتی در خودتان مشاهده کردید.","audioFile":"class-02-fa.mp3"},{"order":3,"code":"class_03_christian_doctrine","classTitle":"کلاس ۳: تعالیم مسیحی","title":"تعالیم مسیحی: بنیادهای ایمان و زندگی در پادشاهی خدا","text":"هدف درس\nهدف این درس این است که دانشجو بفهمد ایمان مسیحی باید بر کلام خدا و تعلیم صحیح بنا شود. احساسات، فرهنگ، تجربه شخصی یا نظر مردم نمی‌توانند جای کلام خدا را بگیرند. ایماندار باید بداند چه باور دارد، چرا باور دارد و چگونه بر اساس آن زندگی کند.\n\n۱. برتری کتاب‌مقدس\nکتاب‌مقدس شامل کلام خداست و معیار نهایی ایمان، رفتار، خدمت و تعلیم مسیحی است. دوم تیموتائوس ۳:۱۶-۱۷ می‌گوید تمام کتاب از الهام خداست و برای تعلیم، تنبیه، اصلاح و تربیت در عدالت مفید است. یعنی کتاب‌مقدس فقط کتابی تاریخی نیست؛ بلکه پیام زنده خدا برای ساختن انسان در تصویر الهی است.\n\nکلام خدا فکر، اراده، نقشه و هدف خدا را آشکار می‌کند. وقتی ایماندار کلام را می‌خواند، فقط اطلاعات دریافت نمی‌کند؛ بلکه ذهن او تازه می‌شود و تصویر مسیح در او بنا می‌گردد.\n\n۲. زندگی در دو جهان\nکولسیان ۱:۱۳ می‌گوید خدا ما را از قدرت تاریکی رهانیده و به پادشاهی پسر محبت خود منتقل کرده است. ایماندار هنوز در جهان فیزیکی زندگی می‌کند، اما متعلق به پادشاهی خداست. عیسی در یوحنا ۱۸:۳۶ فرمود پادشاهی من از این جهان نیست. این به معنای غیرواقعی بودن پادشاهی خدا نیست؛ بلکه یعنی منشأ، قانون و قدرت آن روحانی و برتر از نظام دنیا است.\n\nرومیان ۱۲:۲ می‌گوید هم‌شکل این جهان مشوید، بلکه با تازه شدن ذهن دگرگون شوید. ایماندار باید بیاموزد که ارزش‌ها، تصمیم‌ها، ترس‌ها و امیدهای خود را بر اساس پادشاهی خدا تنظیم کند، نه بر اساس فشار جامعه یا نظام دنیا.\n\n۳. دکترین چیست؟\nدکترین یعنی مجموعه‌ای شناخته‌شده از باورها، تعالیم، ارزش‌ها یا دستورالعمل‌هایی که گروهی از مردم به آن ایمان دارند، آن را تعلیم می‌دهند و بر اساس آن زندگی می‌کنند. در مسیحیت، دکترین از کتاب‌مقدس گرفته می‌شود، نه از فرهنگ، سنت انسانی، تجربه شخصی یا احساسات. اول تیموتائوس ۴:۱ هشدار می‌دهد که آموزه‌های غلط می‌توانند مردم را منحرف کنند. بنابراین دکترین صحیح محافظ ایمان است.\n\n۴. دکترین عدالت و جایگزینی\nدوم قرنتیان ۵:۲۱ می‌گوید: «او را که گناه نشناخت، در راه ما گناه ساخت تا ما در وی عدالت خدا شویم.» این آیه دکترین جایگزینی را نشان می‌دهد. عیسی جای ما را گرفت. اگر او واقعاً برای ما گناه شد، ما نیز واقعاً در او عدالت خدا شده‌ایم. عدالت فقط رفتار درست نیست؛ طبیعت و جایگاهی است که خدا در مسیح به ما داده است.\n\nرومیان ۵:۱۷ عدالت را «هدیه» می‌نامد. همان‌طور که انسان با تولد طبیعی انسان می‌شود، ایماندار با تولد تازه طبیعت عدالت را دریافت می‌کند. او برای عادل شدن اعمال خوب انجام نمی‌دهد؛ چون عادل شده، توانایی انجام اعمال درست را دارد.\n\n۵. توبه از اعمال مرده و ایمان به خدا\nعبرانیان ۶:۱-۲ چند تعلیم بنیادین را معرفی می‌کند. نخست توبه از اعمال مرده است. اعمال مرده یعنی تلاش‌های انسانی برای کسب پذیرش نزد خدا، در حالی که کار کامل مسیح کافی است. عبرانیان ۹:۱۲-۱۴ می‌گوید خون مسیح وجدان ما را از اعمال مرده پاک می‌کند تا خدا را خدمت کنیم.\n\nایمان به خدا نیز بنیاد زندگی مسیحی است. عبرانیان ۱۱:۱ می‌گوید ایمان حقیقت چیزهایی است که به آن امید داریم و برهان چیزهایی است که نمی‌بینیم. دوم قرنتیان ۵:۷ می‌گوید ما با ایمان راه می‌رویم، نه با دیدن. ایمان تلاش سخت برای باور کردن نیست؛ پاسخ قلب انسان به کلام خداست.\n\n۶. تعمیدها\nواژه تعمید به معنی فرو بردن یا غوطه‌ور ساختن است. تعمید روح‌القدس در بدن مسیح هنگام تولد تازه رخ می‌دهد. تعمید آب نشانه بیرونی ایمان و اتحاد با مرگ، دفن و قیام مسیح است. رومیان ۶:۳-۵ نشان می‌دهد که ایماندار با مسیح در مرگ و قیام او متحد شده است. تعمید آب نجات را ایجاد نمی‌کند، بلکه شهادت بیرونی حقیقتی است که در شخص اتفاق افتاده است.\n\n۷. دست‌گذاری\nدست‌گذاری در کتاب‌مقدس برای انتقال برکت، شفا، دریافت روح‌القدس، انتقال عطایای روحانی یا تأیید خدمت دیده می‌شود. مرقس ۱۶:۱۸ از دست‌گذاری برای شفا سخن می‌گوید؛ اعمال ۱۹:۶ از دریافت روح‌القدس؛ اول تیموتائوس ۴:۱۴ از عطای روحانی؛ و اعمال ۱۳:۱-۳ از جدا کردن افراد برای خدمت.\n\n۸. قیامت مردگان و داوری ابدی\nمسیحیت تعلیم می‌دهد که مرگ پایان وجود انسان نیست. یوحنا ۵:۲۸-۲۹ و اول تسالونیکیان ۴:۱۳-۱۷ از قیامت سخن می‌گویند. برای ایماندار، مرگ شکست نهایی نیست، زیرا امید قیامت وجود دارد. داوری نیز دو جنبه دارد: کرسی داوری مسیح برای پاداش ایمانداران و داوری تخت سفید برای محکومیت بی‌ایمانان، همان‌طور که مکاشفه ۲۰:۱۱-۱۵ تعلیم می‌دهد.\n\n۹. تقدیس و قدوسیت\nتقدیس یعنی جدا شدن برای هدف الهی. اول قرنتیان ۶:۱۱ می‌گوید شما شسته، تقدیس و عادل شمرده شده‌اید. تقدیس دو جنبه دارد: نخست، جدایی ایماندار از جهان در لحظه تولد تازه؛ دوم، فرایند پیوسته تازه شدن ذهن و زندگی به وسیله کلام و روح. یوحنا ۱۷:۱۷ می‌گوید: «ایشان را به راستی خود تقدیس نما؛ کلام تو راستی است.» قدوسیت نیز از حضور خدا ناشی می‌شود. چون روح‌القدس در شما ساکن است، بدن شما معبد اوست.\n\n۱۰. رهایی\nکولسیان ۱:۱۳ می‌گوید خدا ما را از قدرت تاریکی رهانیده است. این اتفاق قبلاً در مسیح انجام شده است. کولسیان ۲:۱۵ نشان می‌دهد که مسیح قدرت‌های تاریکی را شکست داد. بنابراین ایماندار نباید خود را زیر سلطه شیطان بداند. او در نام عیسی اقتدار دارد و می‌تواند در آزادی مسیح زندگی کند.\n\nمثال عملی\nخانه‌ای که روی شن ساخته شود، در طوفان فرو می‌ریزد؛ اما خانه‌ای که روی صخره استوار است، می‌ایستد. دکترین صحیح همان صخره است. اگر ایماندار نداند عدالت چیست، نجات چیست، ایمان چیست و جایگاه او در مسیح چیست، هر باد تعلیم یا احساس می‌تواند او را تکان دهد.\n\nجمع‌بندی\nتعالیم مسیحی ستون‌های ایمان هستند. کتاب‌مقدس معیار نهایی است. ایماندار در پادشاهی خدا زندگی می‌کند، با عدالت خدا عادل شده، با ایمان راه می‌رود، تقدیس شده، رها شده و برای زندگی مقدس و مؤثر در بدن مسیح آماده می‌شود.","keyScriptures":"دوم تیموتائوس ۳:۱۶-۱۷؛ کولسیان ۱:۱۳؛ یوحنا ۸:۲۳؛ یوحنا ۱۸:۳۶؛ رومیان ۱۲:۲؛ یوحنا ۱۵:۱۹؛ کولسیان ۳:۱-۲؛ عبرانیان ۱۲:۲۲؛ اول تیموتائوس ۴:۱؛ دوم قرنتیان ۵:۲۱؛ رومیان ۵:۱۷؛ عبرانیان ۶:۱-۲؛ عبرانیان ۹:۱۲-۱۴؛ عبرانیان ۱۱:۱-۶؛ رومیان ۱:۱۷؛ دوم قرنتیان ۵:۷؛ رومیان ۶:۳-۵؛ اول پطرس ۳:۲۱؛ مرقس ۱۶:۱۸؛ اعمال ۱۹:۶؛ اول تیموتائوس ۴:۱۴؛ اعمال ۱۳:۱-۳؛ یوحنا ۵:۲۸-۲۹؛ اول تسالونیکیان ۴:۱۳-۱۷؛ مکاشفه ۲۰:۱۱-۱۵؛ اول قرنتیان ۶:۱۱ و ۱۹؛ یوحنا ۱۷:۱۷؛ کولسیان ۱:۱۲-۱۳؛ کولسیان ۲:۱۵؛ فیلیپیان ۲:۹-۱۱","assignment":"توضیح دهید چرا دکترین صحیح برای ثبات زندگی مسیحی ضروری است. سپس یکی از آموزه‌های این درس را انتخاب کنید و بنویسید چگونه آن را در زندگی روزانه خود به کار می‌گیرید.","audioFile":"class-03-fa.mp3"},{"order":4,"code":"class_04a_evangelism","classTitle":"کلاس ۴A: بشارت","title":"بشارت: از نجات جان تا شاگردسازی","text":"هدف درس\nهدف این درس این است که دانشجو بفهمد بشارت فقط گفتن چند جمله مذهبی نیست؛ بشارت رساندن پیامی است که زندگی ما را تغییر داده تا زندگی دیگری نیز تغییر کند. اما کار خدا در نجات جان‌ها با یک گفت‌وگوی کوتاه پایان نمی‌یابد. هدف نهایی، شاگردسازی، پیگیری، تعلیم و اتصال شخص به بدن مسیح است.\n\n۱. بشارت چیست؟\nبشارت یعنی رساندن خبر خوش انجیل به شخص دیگر. این همان پیامی است که ما به آن ایمان آوردیم و زندگی ما را عوض کرد. وقتی درباره عیسی، مرگ، قیام، نجات، آمرزش، حیات تازه و پادشاهی خدا سخن می‌گوییم، در حال انتقال پیام حیات هستیم.\n\nمرقس ۱۶:۱۵ می‌گوید: «به تمام عالم بروید و جمیع خلایق را به انجیل موعظه کنید.» این فرمان برای گروه کوچکی از متخصصان نیست؛ مسئولیت تمام ایمانداران است. هر کسی که نجات یافته، اکنون حامل پیام نجات برای دیگران است.\n\n۲. تفاوت نجات جان و بردن جان برای خدا\nممکن است کسی پیام انجیل را بشنود و دعا کند، اما اگر رها شود، رشد نکند، به کلیسا وصل نشود و تعلیم نبیند، کار کامل نشده است. در متی ۲۸:۱۹-۲۰، عیسی فقط نگفت بروید و موعظه کنید؛ فرمود بروید، همه ملت‌ها را شاگرد سازید، تعمید دهید و تعلیم دهید که آنچه فرمان داده‌ام نگاه دارند. بنابراین بشارت کامل، به شاگردسازی ختم می‌شود.\n\nمثال ساده این است: اگر مادری کودکی به دنیا آورد، کارش با تولد کودک تمام نمی‌شود. کودک باید تغذیه، مراقبت، آموزش و رشد داشته باشد. کسی که تازه ایمان می‌آورد نیز باید مراقبت شود، به کلام خدا تغذیه شود و در مشارکت کلیسا قرار گیرد.\n\n۳. خدا ما را شریک نجات دیگران کرده است\nدوم قرنتیان ۵:۱۸-۲۰ می‌گوید خدا ما را به واسطه مسیح با خود آشتی داد و خدمت آشتی را به ما سپرد. این یعنی خدا فقط ما را نجات نداد؛ ما را نماینده پیام آشتی قرار داد. اکنون ایماندار سفیر مسیح است. وقتی با کسی درباره انجیل سخن می‌گویید، فقط نظر شخصی خود را نمی‌گویید؛ پیام پادشاهی خدا را حمل می‌کنید.\n\n۴. چرا باید بشارت بدهیم؟\nاول، چون عیسی فرمان داده است. دوم، چون انسان‌ها بدون شنیدن پیام نمی‌توانند ایمان بیاورند. رومیان ۱۰:۱۴-۱۵ می‌پرسد چگونه ایمان بیاورند به کسی که درباره او نشنیده‌اند؟ سوم، چون محبت خدا در ماست و نمی‌توانیم نسبت به سرنوشت مردم بی‌تفاوت باشیم. چهارم، چون بشارت باعث رشد خود ما نیز می‌شود. وقتی درباره مسیح شهادت می‌دهیم، ایمان ما فعال‌تر می‌شود.\n\n۵. نقش روح‌القدس در بشارت\nاعمال ۱:۸ نشان می‌دهد که روح‌القدس ما را برای شهادت دادن توانمند می‌کند. بشارت با قدرت انسانی انجام نمی‌شود. ما با محبت، حکمت و هدایت روح سخن می‌گوییم. ممکن است شما همه پاسخ‌ها را ندانید، اما می‌توانید شهادت دهید که عیسی در زندگی شما چه کرده است. روح‌القدس دل‌ها را لمس می‌کند و کلام خدا را زنده می‌سازد.\n\n۶. پیگیری پس از بشارت\nاگر کسی پیام را پذیرفت، باید پیگیری شود. پیگیری یعنی تماس گرفتن، دعا کردن، فرستادن آیه یا تعلیم، دعوت به جلسه کلیسا، پاسخ دادن به پرسش‌ها و کمک به او برای شروع زندگی مسیحی. هدف این است که شخص تنها نماند. بشارت بدون پیگیری مثل کاشتن بذر بدون آبیاری است.\n\n۷. استفاده از ابزارهای موجود برای ثبت و پیگیری\nدر خدمت، ابزارهایی برای ثبت کار بشارت و پیگیری افراد وجود دارد. در اپلیکیشن کلیسا نیز می‌توان بخشی برای ثبت نام کسانی که به آنان بشارت داده‌ایم، وضعیت پیگیری، درخواست دعا و دعوت به کلیسا ایجاد کرد. ثبت کردن به ما کمک می‌کند مسئولانه‌تر عمل کنیم و هیچ جان تازه‌ای فراموش نشود.\n\n۸. بشارت سبک زندگی است\nبشارت فقط یک برنامه ماهانه نیست؛ سبک زندگی ایماندار است. در محل کار، خانواده، دانشگاه، خیابان، فضای مجازی و ارتباطات روزمره، فرصت‌هایی برای نشان دادن محبت خدا و گفتن پیام انجیل وجود دارد. البته باید با حکمت، احترام و محبت عمل کرد. هدف ما بحث کردن یا شکست دادن طرف مقابل نیست؛ هدف رساندن نور، حیات و امید است.\n\nمثال عملی\nاگر شما دارویی را پیدا کنید که جان کسی را نجات می‌دهد، محبت اجازه نمی‌دهد آن را فقط برای خود نگه دارید. انجیل پیام حیات است. کسی که حیات را دریافت کرده، با محبت و مسئولیت آن را به دیگران می‌رساند.\n\nجمع‌بندی\nبشارت یعنی رساندن پیام حیات، اما کار کامل با شاگردسازی، پیگیری و اتصال شخص به کلیسا انجام می‌شود. هر مسیحی مسئول بشارت است. خدا ما را سفیران آشتی قرار داده است. بنابراین با دعا، محبت، حکمت و هدایت روح‌القدس، جان‌ها را به مسیح نزدیک کنیم و آنان را در مسیر رشد تنها نگذاریم.","keyScriptures":"متی ۲۸:۱۹-۲۰؛ مرقس ۱۶:۱۵؛ دوم قرنتیان ۵:۱۷-۲۰؛ اعمال ۱:۸؛ یوحنا ۱۵:۱۶؛ رومیان ۱۰:۱۴-۱۵؛ اول قرنتیان ۹:۱۶؛ دانیال ۱۲:۳؛ امثال ۱۱:۳۰؛ لوقا ۱۵:۴-۷","assignment":"نام چند نفر را که می‌خواهید برایشان دعا کنید و انجیل را با آنان در میان بگذارید بنویسید. سپس برای یکی از آنان برنامه پیگیری، دعا و دعوت به مشارکت کلیسا را توضیح دهید.","audioFile":"class-04a-fa.mp3"},{"order":5,"code":"class_04b_cell_ministry","classTitle":"کلاس ۴B: خدمت سلولی","title":"خدمت سلولی: رشد، مراقبت و مشارکت هر عضو در بدن مسیح","text":"هدف درس\nهدف این درس این است که دانشجو بفهمد خدمت سلولی یک برنامه جانبی یا انتخابی نیست، بلکه ساختاری عملی برای رشد، مراقبت، شاگردسازی، بشارت و مشارکت هر عضو در بدن مسیح است. کلیسا فقط جلسه عمومی نیست؛ بدن زنده‌ای است که هر عضو باید در آن رشد کند و سهم خود را ادا نماید.\n\n۱. خدمت سلولی چیست؟\nخدمت سلولی محیطی کوچک‌تر و نزدیک‌تر برای مشارکت، دعا، تعلیم، مراقبت و رشد است. در جلسه عمومی کلیسا، جمع بزرگ برکت می‌گیرد؛ اما در گروه سلولی، شخص فرصت بیشتری برای ارتباط، سؤال، خدمت، مسئولیت‌پذیری و رشد عملی دارد. افسسیان ۴:۱۱-۱۶ نشان می‌دهد که هدف خدمات کلیسایی، تجهیز مقدسین و بنای بدن مسیح است تا هر عضو رشد کند و سهم خود را برای رشد بدن بدهد.\n\n۲. هر عضو باید رشد کند و مشارکت داشته باشد\nکلیسا زمانی قوی می‌شود که اعضای آن رشد کنند. اول قرنتیان ۱۲ بدن مسیح را به بدن انسان تشبیه می‌کند: چشم، دست، پا و اعضای دیگر هر کدام کار خود را دارند. هیچ عضوی بی‌اهمیت نیست. اگر یک عضو غیر فعال بماند، بخشی از بدن از کار می‌افتد. خدمت سلولی کمک می‌کند هر عضو جایگاه خود را پیدا کند و از حالت تماشاگر به شریک فعال تبدیل شود.\n\n۳. خدمت سلولی برای ثبات تازه‌ایمانان ضروری است\nتازه‌ایمانان نیاز به مراقبت، پاسخ به پرسش‌ها، دعا و همراهی دارند. اگر کسی تازه ایمان بیاورد اما در خانواده روحانی قرار نگیرد، ممکن است در برابر فشارها ضعیف شود. اعمال ۲:۴۲-۴۷ نشان می‌دهد ایمانداران اولیه در تعلیم رسولان، مشارکت، شکستن نان و دعا ثابت بودند. این الگو نشان می‌دهد رشد مسیحی در فضای مشارکت اتفاق می‌افتد.\n\n۴. خدمت سلولی فقط یک برنامه نیست\nخدمت سلولی فقط یکی از برنامه‌های کلیسا نیست؛ بلکه راهی است که کلیسا از طریق رشد و توسعه اعضا رشد می‌کند. وقتی هر عضو دعا کند، بشارت دهد، تازه‌ایمانان را پیگیری کند، در کلام رشد کند و دیگران را تشویق کند، کلیسا به‌طور طبیعی و سالم رشد می‌کند. رشد واقعی کلیسا فقط با زیاد شدن تعداد صندلی‌ها نیست؛ با بالغ شدن انسان‌ها در مسیح است.\n\n۵. فواید خدمت سلولی برای دانشجو\nخدمت سلولی به دانشجو کمک می‌کند تنها نماند، در ایمان پاسخ‌گو باشد، کلام را بهتر بفهمد، به دعا عادت کند، در خدمت فعال شود، دوستان روحانی سالم داشته باشد و برای بشارت تشویق شود. عبرانیان ۱۰:۲۴-۲۵ می‌گوید یکدیگر را به محبت و اعمال نیکو ترغیب کنیم و از گرد آمدن با هم غفلت نکنیم.\n\n۶. نقش دانشجو در گروه سلولی\nدانشجو نباید فقط مصرف‌کننده باشد. او می‌تواند دعا کند، آیه‌ای به اشتراک بگذارد، کسی را دعوت کند، تازه‌ایمانی را پیگیری کند، در نظم جلسه کمک کند، شهادت بدهد، برای نیازهای دیگران دعا کند و در پروژه‌های بشارتی شرکت کند. رومیان ۱۲:۴-۸ نشان می‌دهد عطایا و نقش‌های مختلفی در بدن وجود دارد.\n\n۷. خدمت سلولی و شاگردسازی\nدوم تیموتائوس ۲:۲ اصل انتقال تعلیم را بیان می‌کند: آنچه آموخته‌ای به افراد امین بسپار تا آنان نیز دیگران را تعلیم دهند. این اصل در گروه سلولی عملی می‌شود. یک نفر رشد می‌کند، سپس به دیگری کمک می‌کند رشد کند. این زنجیره شاگردسازی، کلیسا را از درون قوی می‌سازد.\n\n۸. خدمت سلولی و بشارت\nگروه سلولی یک پایگاه بشارت است. اعضا می‌توانند برای خانواده‌ها، دوستان، همکاران و همسایگان دعا کنند؛ افراد جدید را دعوت کنند؛ نیازهای آنان را پیگیری کنند؛ و آنان را به مدرسه، کلیسا و رشد در کلام وصل نمایند. بنابراین خدمت سلولی پلی است بین بشارت، مراقبت و عضویت فعال در کلیسا.\n\nمثال عملی\nذغال تنها اگر از آتش جدا شود، به‌تدریج خاموش می‌شود؛ اما وقتی در کنار ذغال‌های دیگر بماند، گرمای آن حفظ می‌شود. ایماندار نیز اگر از مشارکت جدا شود، ضعیف می‌شود؛ اما در محیط دعا، کلام و محبت، شعله ایمان او قوی‌تر می‌گردد.\n\nجمع‌بندی\nخدمت سلولی یک مسیر الهی برای رشد هر عضو و گسترش کلیساست. در آن، هر شخص دیده می‌شود، مراقبت می‌شود، رشد می‌کند و خدمت می‌آموزد. دانشجو باید تصمیم بگیرد که در کلیسا فقط حضور نداشته باشد، بلکه فعالانه در رشد بدن مسیح مشارکت کند.","keyScriptures":"افسسیان ۴:۱۱-۱۶؛ اعمال ۲:۴۲-۴۷؛ اول قرنتیان ۱۲:۱۲-۲۷؛ عبرانیان ۱۰:۲۴-۲۵؛ متی ۲۸:۱۹-۲۰؛ دوم تیموتائوس ۲:۲؛ کولسیان ۲:۱۹؛ رومیان ۱۲:۴-۸","assignment":"توضیح دهید چرا مشارکت در گروه سلولی برای رشد شما مهم است. سپس بنویسید در گروه سلولی چگونه می‌توانید دعا کنید، خدمت کنید، دیگران را تشویق کنید و در بشارت سهم داشته باشید.","audioFile":"class-04b-fa.mp3"},{"order":6,"code":"class_05_character_prosperity","classTitle":"کلاس ۵: شخصیت مسیحی و کامیابی","title":"شخصیت مسیحی و کامیابی: رشد از جلال به جلال","text":"هدف درس\nهدف این درس این است که دانشجو بفهمد تولد تازه باید در شخصیت، رفتار، گفتار، روابط، تصمیم‌ها و نگرش او نسبت به کامیابی دیده شود. نجات در لحظه دریافت می‌شود، اما رشد مسیحی تدریجی است. خلقت تازه باید در زندگی بیرونی به صورت شخصیت مسیحی و زندگی ثمربخش ظاهر شود.\n\n۱. نجات فوری است، رشد تدریجی است\nوقتی شخص عیسی را می‌پذیرد، بلافاصله نجات می‌یابد و حیات تازه دریافت می‌کند. اما رشد شخصیت، تازه شدن ذهن، کنترل زبان، نظم، محبت، صبر، وفاداری و بلوغ روحانی فرایندی پیوسته است. دوم قرنتیان ۳:۱۸ می‌گوید ما با نگاه کردن به جلال خداوند، به همان صورت از جلال به جلال تبدیل می‌شویم. این یعنی رشد مسیحی یک حرکت پیوسته و پیش‌رونده است.\n\n۲. شخصیت مسیحی از درون آغاز می‌شود\nاول قرنتیان ۶:۱۷ می‌گوید کسی که به خداوند می‌پیوندد، با او یک روح است. این حقیقت نشان می‌دهد که ایماندار در درون خود طبیعت الهی دریافت کرده است. اما این طبیعت باید در رفتار و شخصیت بیرونی او ظاهر شود. افسسیان ۵:۱۸-۲۱ می‌گوید از روح پر شوید. وقتی انسان تحت تأثیر روح‌القدس زندگی می‌کند، شخصیت او شکل الهی می‌گیرد.\n\n۳. آینه کلام خدا\nدوم قرنتیان ۳:۱۸ از نگاه کردن در آینه سخن می‌گوید. آینه خدا کلام اوست. وقتی به کلام نگاه می‌کنیم، می‌فهمیم در مسیح چه کسی هستیم و چگونه باید زندگی کنیم. کلام خدا فقط عیب‌ها را نشان نمی‌دهد؛ تصویر واقعی ما در مسیح را آشکار می‌کند. هرچه بیشتر در کلام بمانیم، بیشتر به همان صورتی که می‌بینیم تبدیل می‌شویم.\n\n۴. ثمرات روح در زندگی ایماندار\nغلاطیان ۵:۲۲-۲۳ ثمرات روح را معرفی می‌کند: محبت، شادی، سلامتی، حلم، مهربانی، نیکویی، ایمان، فروتنی و خویشتنداری. این‌ها فقط رفتارهای اخلاقی نیستند؛ نشانه‌های طبیعت تازه‌اند. ایماندار باید در روابط، خانواده، کار، کلیسا و جامعه این صفات را نشان دهد.\n\n۵. مراقبت از روابط و تأثیرات\nاول قرنتیان ۱۵:۳۳ می‌گوید معاشرت‌های بد اخلاق خوب را فاسد می‌کند. این یک پیشنهاد نیست؛ یک حقیقت است. ارتباطات انسان بر فکر، زبان، تصمیم و آینده او اثر می‌گذارد. اگر ایماندار می‌خواهد شخصیت مسیحی رشد کند، باید مراقب باشد چه کسانی بیشترین تأثیر را بر او دارند، چه چیزهایی می‌شنود، چه محتواهایی می‌بیند و با چه ارزش‌هایی همراه می‌شود.\n\n۶. کامیابی پادشاهی چیست؟\nکامیابی پادشاهی فقط داشتن پول نیست. سوم یوحنا ۱:۲ نشان می‌دهد که خدا خواهان کامیابی و سلامتی ماست، همان‌گونه که جان ما کامیاب است. کامیابی حقیقی یعنی زندگی در هدف خدا، رشد در شخصیت، برکت بودن برای دیگران، استفاده درست از منابع، دادن، خدمت کردن و جلو بردن انجیل.\n\n۷. نسل ابراهیم و برکت بودن\nغلاطیان ۳:۲۹ می‌گوید اگر از آن مسیح هستید، نسل ابراهیم و وارثان وعده‌اید. خدا به ابراهیم گفت تو را برکت می‌دهم و تو برکت خواهی بود. بنابراین ایماندار فقط برای دریافت برکت زندگی نمی‌کند؛ او خود به کانال برکت تبدیل می‌شود. برکت بودن یعنی زندگی من باعث بلند شدن، تقویت، رشد و نجات دیگران شود.\n\n۸. اصل دادن\nاعمال ۲۰:۳۵ می‌گوید دادن مبارک‌تر از گرفتن است. کامیابی پادشاهی با گرفتن شروع نمی‌شود، بلکه با دادن آغاز می‌شود. دوم قرنتیان ۹:۶-۸ تعلیم می‌دهد که کسی که با برکت می‌کارد، با برکت نیز درو خواهد کرد. دادن فقط پول نیست؛ وقت، محبت، خدمت، توجه، دعا، مهارت و منابع نیز شامل می‌شود. اما دادن مالی نیز بخشی مهم از انضباط پادشاهی است، زیرا قلب انسان را از خودمحوری آزاد می‌کند.\n\n۹. شخصیت و کامیابی به هم مربوط‌اند\nاگر شخصیت رشد نکند، کامیابی می‌تواند خطرناک شود. خدا می‌خواهد ما هم در منابع رشد کنیم و هم در حکمت، وفاداری، فروتنی و محبت. شخصیت ظرف برکت است. هرچه ظرف شخصیت وسیع‌تر و پاک‌تر شود، شخص می‌تواند برکت بیشتری را برای هدف خدا حمل کند.\n\nمثال عملی\nدرخت سالم فقط با برگ‌های زیبا شناخته نمی‌شود، بلکه با میوه‌اش شناخته می‌شود. ایماندار نیز فقط با گفتن «من مسیحی هستم» شناخته نمی‌شود؛ بلکه با ثمره شخصیت، محبت، وفاداری، خدمت و برکت بودن شناخته می‌شود.\n\nجمع‌بندی\nخلقت تازه باید شخصیت تازه و سبک زندگی تازه ظاهر کند. رشد مسیحی تدریجی است اما باید پیوسته باشد. کلام خدا آینه ماست، روح‌القدس شخصیت خدا را در ما ظاهر می‌کند، روابط صحیح به رشد کمک می‌کند و کامیابی حقیقی یعنی زندگی برای هدف خدا و برکت بودن برای دیگران.","keyScriptures":"اول قرنتیان ۶:۱۷؛ افسسیان ۵:۱۸-۲۱؛ دوم قرنتیان ۳:۱۸؛ غلاطیان ۵:۲۲-۲۳؛ اول قرنتیان ۱۵:۳۳؛ پیدایش ۱۲:۲-۳؛ غلاطیان ۳:۱۳-۱۴ و ۲۹؛ اعمال ۲۰:۳۵؛ دوم قرنتیان ۹:۶-۸؛ سوم یوحنا ۱:۲؛ رومیان ۱۲:۱-۲؛ متی ۵:۱۴-۱۶","assignment":"سه بخش از شخصیت خود را که نیاز به رشد دارد بنویسید. سپس برای هرکدام یک تصمیم عملی بنویسید. همچنین توضیح دهید چگونه می‌توانید در دادن، خدمت و برکت بودن رشد کنید.","audioFile":"class-05-fa.mp3"},{"order":7,"code":"class_06_local_assembly","classTitle":"کلاس ۶: کلیسای محلی","title":"کلیسای محلی: خانواده روحانی، رشد و عضویت مسئولانه","text":"هدف درس\nهدف این درس این است که دانشجو بفهمد کلیسا فقط یک مکان، برنامه یا جلسه مذهبی نیست؛ کلیسا بدن مسیح، خانواده روحانی و ساختار الهی برای رشد، مراقبت، خدمت و انجام مأموریت خدا در زمین است. هر ایماندار باید در یک کلیسای محلی مشخص قرار بگیرد و در آن رشد کند.\n\n۱. کلیسای جهانی چیست؟\nواژه کلیسا از مفهوم «خوانده‌شدگان» می‌آید. کلیسای جهانی شامل تمام بدن مسیح در زمین است؛ همه کسانی که در مسیح تولد تازه یافته‌اند و متعلق به خداوند هستند. عیسی در متی ۱۶:۱۸ فرمود: «کلیسای خود را بنا می‌کنم.» این نشان می‌دهد کلیسا نقشه انسانی نیست؛ کار مسیح است.\n\n۲. کلیسای محلی چیست؟\nکلیسای جهانی در نقاط مختلف جهان به صورت کلیساهای محلی دیده می‌شود. کلیسای محلی جمع مشخصی از ایمانداران است که تحت رهبری، تعلیم، مشارکت، خدمت و مأموریت مشترک گرد هم می‌آیند. هر ایماندار باید در یک کلیسای محلی ریشه بگیرد تا پرورش یابد، رشد کند و نقش خود را در بدن مسیح انجام دهد.\n\n۳. چرا حضور در کلیسا ضروری است؟\nعضویت در کلیسای محلی فقط نام نویسی نیست؛ تعهد به مشارکت، رشد، خدمت و پاسخ‌گویی است. عبرانیان ۱۰:۲۴-۲۵ می‌گوید از گرد آمدن با یکدیگر غفلت نکنیم. برخی می‌گویند «من در خانه هم می‌توانم خدا را عبادت کنم.» درست است که می‌توان در خانه دعا کرد، اما برکات خاصی وجود دارد که فقط در مشارکت بدن مسیح دریافت می‌شود: تعلیم، اصلاح، تشویق، دعا، پرستش جمعی، خدمت و رشد در روابط.\n\n۴. کلیسا محل تغذیه و پرورش است\nافسسیان ۴:۱۱-۱۶ نشان می‌دهد خدا خدماتی در کلیسا قرار داده تا مقدسین تجهیز شوند و بدن مسیح بنا گردد. بدون کلیسا، ایماندار ممکن است از تغذیه منظم کلام، مراقبت شبانی، نظم روحانی و فرصت خدمت محروم شود. مزامیر ۹۲:۱۳-۱۴ می‌گوید کسانی که در خانه خداوند غرس شده‌اند، خواهند شکفت و حتی در پیری نیز ثمر خواهند داد. رشد پایدار نیاز به ریشه داشتن دارد.\n\n۵. هر عضو نقش دارد\nاول قرنتیان ۱۲:۱۲-۱۸ بدن را به اعضای مختلف تشبیه می‌کند. هیچ عضوی نمی‌تواند بگوید به دیگری نیاز ندارد. همچنین هیچ عضوی نباید بگوید من مهم نیستم. در کلیسا، هر شخص نقشی دارد: دعا، تشویق، خدمت، بشارت، کمک عملی، تعلیم، مهمان‌نوازی، مشارکت مالی، مراقبت از تازه‌ایمانان و بسیاری خدمات دیگر.\n\n۶. مسئولیت اول عضو کلیسای محلی\nاولین مسئولیت شخصی عضو کلیسا حضور منظم در جلسات عمومی است. هیچ‌کس نمی‌تواند به جای شما حضور پیدا کند، به جای شما گوش دهد، به جای شما در پرستش جمعی بایستد یا به جای شما در مشارکت رشد کند. حضور منظم نشان‌دهنده ارزش دادن به خانه خدا، کلام خدا و خانواده روحانی است.\n\n۷. کلیسا ستون و پایه حقیقت است\nاول تیموتائوس ۳:۱۵ کلیسا را خانه خدا و ستون و بنیاد حقیقت معرفی می‌کند. در جهانی که افکار، ارزش‌ها و تعلیم‌های گوناگون مردم را می‌کشد، کلیسا جایی است که حقیقت کلام خدا اعلام، حفظ و منتقل می‌شود. دانشجو باید کلیسا را منبع ثبات، تعلیم و جهت روحانی بداند.\n\n۸. عضویت رسمی یعنی چه؟\nعضویت رسمی فقط حضور گاه‌به‌گاه نیست. یعنی شخص خود را به این خانواده روحانی، تعلیم، نظم، مأموریت و رهبری کلیسا متعهد می‌داند. گذراندن مدرسه آنلاین امیدنو۷ کمک می‌کند شخص بنیادهای ایمان، مسئولیت‌ها و مسیر رشد را بشناسد تا عضویت او آگاهانه، سالم و مسئولانه باشد.\n\nمثال عملی\nنهال اگر هر روز از خاکی به خاک دیگر منتقل شود، ریشه نمی‌گیرد و ثمر نمی‌دهد. ایماندار نیز اگر به کلیسای محلی متعهد نشود، رشد او ناپایدار می‌شود. خدا می‌خواهد ما در خانه روحانی غرس شویم تا ریشه بگیریم، رشد کنیم و ثمر بیاوریم.\n\nجمع‌بندی\nکلیسای محلی خانواده روحانی و محل رشد ایماندار است. هر مسیحی باید در کلیسای محلی عضو، حاضر، فعال و مسئول باشد. در کلیسا، شخص تعلیم می‌گیرد، رشد می‌کند، خدمت می‌آموزد و در مأموریت خدا سهم می‌یابد. عضویت رسمی در کلیسای امیدنو۷ باید همراه با شناخت، تعهد و تکمیل این مسیر آموزشی باشد.","keyScriptures":"متی ۱۶:۱۸؛ افسسیان ۴:۱۱-۱۶؛ اول قرنتیان ۱۲:۱۲-۱۸؛ اعمال ۲:۴۲؛ عبرانیان ۱۰:۲۴-۲۵؛ مزامیر ۹۲:۱۳-۱۴؛ اول تیموتائوس ۳:۱۵؛ رومیان ۱۲:۴-۵؛ اول پطرس ۲:۵؛ متی ۵:۱۴-۱۶","assignment":"توضیح دهید چرا هر ایماندار به کلیسای محلی نیاز دارد. سپس بنویسید چگونه می‌خواهید در کلیسای امیدنو۷ عضو فعال، وفادار و مسئول باشید.","audioFile":"class-06-fa.mp3"},{"order":8,"code":"class_07_mobile_technology","classTitle":"کلاس ۷: تکنولوژی موبایل برای رشد شخصی، بشارت و رشد کلیسا","title":"تکنولوژی موبایل: ابزار رشد، بشارت و گسترش کلیسا","text":"هدف درس\nهدف این درس این است که دانشجو بفهمد تکنولوژی فقط برای سرگرمی، خبر، ارتباطات روزمره یا تجارت نیست؛ بلکه می‌تواند ابزاری قدرتمند برای رشد شخصی، دریافت تعلیم، بشارت، شاگردسازی، پیگیری افراد و رشد کلیسا باشد. ایماندار باید یاد بگیرد از ابزارهای زمان خود برای هدف خدا استفاده کند.\n\n۱. تکنولوژی و انجیل\nمرقس ۱۶:۱۵ می‌گوید انجیل باید به همه خلایق اعلام شود. در زمان‌های گذشته، رساندن پیام به شهرها و ملت‌ها زمان زیادی می‌برد. امروز با ابزارهای دیجیتال، یک پیام، یک ویدئو، یک فایل صوتی، یک لینک جلسه یا یک متن تعلیمی می‌تواند در چند ثانیه به افراد بسیاری برسد. این سرعت و دسترسی، مسئولیت ما را بیشتر می‌کند.\n\n۲. تکنولوژی باید در خدمت هدف خدا باشد\nتکنولوژی ذاتاً هدف نهایی نیست؛ ابزار است. همان‌طور که قلم می‌تواند برای نوشتن حقیقت یا دروغ استفاده شود، موبایل و اینترنت نیز می‌تواند برای اتلاف وقت یا گسترش انجیل استفاده شود. ایماندار باید از خود بپرسد: آیا موبایل من فقط مرا مشغول می‌کند یا به رشد روحانی من و خدمت خدا کمک می‌کند؟\n\n۳. رشد شخصی از طریق ابزارهای دیجیتال\nدانشجو می‌تواند از موبایل برای خواندن کتاب‌مقدس، گوش دادن به تعلیم، شرکت در جلسات آنلاین، یادداشت‌برداری، مرور درس‌ها، دعا با برنامه‌ریزی، دریافت اعلان‌های کلیسا و مطالعه روزانه استفاده کند. اگر موبایل هر روز ساعت‌ها وقت انسان را می‌گیرد، باید بخشی از آن زمان به کلام، دعا و رشد اختصاص داده شود.\n\n۴. بشارت از طریق موبایل\nرومیان ۱۰:۱۴-۱۵ نشان می‌دهد مردم باید بشنوند تا ایمان بیاورند. امروز شنیدن می‌تواند از طریق پیام صوتی، ویدئو، لینک جلسه، آیه، شهادت شخصی یا دعوت به کلیسا باشد. یک پیام کوتاه با محبت می‌تواند در زندگی کسی آغازگر کار بزرگی شود. البته باید با حکمت رفتار کرد؛ ارسال زیاد و بدون رابطه ممکن است اثر عکس داشته باشد. بشارت دیجیتال باید شخصی، محترمانه و همراه با پیگیری باشد.\n\n۵. شاگردسازی و پیگیری دیجیتال\nمتی ۲۸:۱۹-۲۰ فقط فرمان بشارت نیست؛ فرمان شاگردسازی است. ابزارهای دیجیتال کمک می‌کنند با تازه‌ایمانان در تماس بمانیم، برایشان آیات بفرستیم، درس‌ها را معرفی کنیم، سؤالاتشان را پاسخ دهیم، آن‌ها را به جلسه آنلاین دعوت کنیم و مسیر رشدشان را پیگیری کنیم. اپلیکیشن کلیسا می‌تواند محل ثبت پیشرفت، درس‌ها، تکالیف، امتحان و مشارکت باشد.\n\n۶. نظم در استفاده از تکنولوژی\nابزار خوب اگر بدون نظم استفاده شود، می‌تواند باعث حواس‌پرتی شود. ایماندار باید زمان استفاده از شبکه‌های اجتماعی، محتوای بی‌فایده و سرگرمی‌های بی‌هدف را مدیریت کند. کولسیان ۴:۵-۶ ما را به حکمت در رفتار و گفتار دعوت می‌کند. در فضای دیجیتال نیز باید گفتار، تصویر، پاسخ و رفتار ما نشان‌دهنده مسیح باشد.\n\n۷. تکنولوژی برای مشارکت کلیسایی\nاپلیکیشن کلیسا می‌تواند اطلاعیه‌ها، جلسات آنلاین، لینک دعا، مدرسه آنلاین، فرم ثبت‌نام، یادداشت‌ها، تکالیف، امتحان، پیگیری اعضا و ارتباطات کلیسا را یکپارچه کند. این باعث می‌شود اعضا حتی اگر از نظر جغرافیایی دور باشند، بتوانند در مسیر تعلیم و مشارکت باقی بمانند.\n\n۸. تکنولوژی و مسئولیت ایماندار\nوقتی ابزار در دست ماست، مسئولیت نیز با ماست. اگر می‌توانیم پیام نجات را به کسی برسانیم و این کار را نکنیم، فرصت را از دست داده‌ایم. اگر می‌توانیم از موبایل برای رشد خود استفاده کنیم اما فقط وقت را تلف کنیم، ابزار را در جهت درست به کار نبرده‌ایم. تکنولوژی باید به خدمت کلام، دعا، محبت، بشارت و رشد کلیسا درآید.\n\nمثال عملی\nچاقو در دست پزشک می‌تواند جان را نجات دهد و در دست شخص نادان می‌تواند آسیب بزند. تکنولوژی نیز چنین است. ارزش آن به هدف و استفاده ما بستگی دارد. ایماندار باید ابزارهای دیجیتال را هوشمندانه، مقدس و هدفمند استفاده کند.\n\nجمع‌بندی\nتکنولوژی موبایل ابزاری مهم برای نسل امروز است. از آن برای رشد شخصی، دریافت تعلیم، بشارت، پیگیری، شاگردسازی و ارتباط با کلیسا استفاده کنید. موبایل شما می‌تواند فقط وسیله سرگرمی باشد یا می‌تواند به ابزاری برای گسترش پادشاهی خدا تبدیل شود. انتخاب با شماست.","keyScriptures":"مرقس ۱۶:۱۵؛ متی ۲۸:۱۹-۲۰؛ اعمال ۱:۸؛ حبقوق ۲:۲؛ دانیال ۱۲:۴؛ رومیان ۱۰:۱۴-۱۵؛ دوم تیموتائوس ۲:۲؛ کولسیان ۴:۵-۶؛ اول قرنتیان ۹:۲۲-۲۳","assignment":"بنویسید چگونه می‌توانید از موبایل و ابزارهای دیجیتال برای رشد شخصی، دریافت تعلیم، بشارت، پیگیری افراد و کمک به رشد کلیسا استفاده کنید. همچنین نام ابزارها یا اپلیکیشن‌هایی را که می‌خواهید منظم‌تر استفاده کنید ذکر کنید.","audioFile":"class-07-fa.mp3"}],"en":[{"order":1,"code":"class_01_new_creature","classTitle":"Class 1: The New Creature","title":"The New Creature: Your New Identity in Christ","text":"Lesson Objective\nThis lesson teaches that receiving Jesus Christ is not merely a moral improvement or a religious decision. It is the new birth and the beginning of a completely new life. The expression “new creature” comes from 2 Corinthians 5:17: “If any man be in Christ, he is a new creature: old things are passed away; behold, all things are become new.” This truth is the foundation of the Christian life.\n\n1. What does “new creature” mean?\nA new creature is a person who has been born again in Christ. He is not the old person slightly improved. In his spirit he has received the life of God. When a person receives Jesus Christ as personal Lord and Savior, he enters a new class of life. His past is no longer his identity. Sin, fear, shame, condemnation, failure, and the dominion of darkness no longer have the right to define him.\n\nJohn 3:16 declares that whoever believes in Jesus should not perish but have everlasting life. This is more than a promise of heaven; it is a transfer from the realm of perishing into the realm of life. Colossians 1:13 says God has delivered us from the power of darkness and translated us into the Kingdom of His dear Son. Therefore, the believer must not see himself as a victim, a defeated person, or a prisoner of the past.\n\n2. Three great things you have received\nFirst, you received eternal life. 1 John 5:11-12 says God has given us eternal life, and this life is in His Son. Eternal life is not only endless existence; it is the quality of God’s own life imparted to the human spirit.\n\nSecond, you received righteousness. Romans 5:18-19 shows that through Christ’s obedience we were brought into righteousness. Righteousness means the ability to stand before God without fear, guilt, inferiority, or condemnation.\n\nThird, you received fellowship with God. 1 John 1:3 and John 17:21 show that God’s purpose was not only to forgive sin, but to bring man into fellowship with Himself. Now you can know God, live with Him, grow in His Word, and be led by His Spirit.\n\n3. Salvation is by grace, not works\nEphesians 2:8-9 teaches that you are saved by grace through faith, not by works. No man qualified you for salvation, and no man can disqualify you from what God has given you in Christ. You received salvation by faith in your heart and confession with your mouth, according to Romans 10:9-10.\n\nGood works are important, but they are not the root of salvation; they are the fruit of the new life. You do not do good works to become saved. Because you are saved, the power to live rightly has been given to you.\n\n4. Assurance of salvation is not based on feelings\nA believer may sometimes say, “I do not feel saved today.” Feelings are not the standard of truth. The two strong witnesses of salvation are the Word of God and the witness of the Holy Spirit in our hearts. Romans 8:16 says the Spirit bears witness with our spirit that we are children of God. When feelings change, truth does not change.\n\n5. Man is a spirit, has a soul, and lives in a body\n1 Thessalonians 5:23 shows that man is spirit, soul, and body. At the new birth, God’s life is received in your spirit. But your mind must be renewed by the Word of God. Romans 12:2 says we are transformed by the renewing of the mind. If the mind is still full of fear, shame, and wrong thinking, the outward life may not yet reflect the new reality. The Word renews the mind and transforms the life.\n\n6. The position of the new creature\nThe new creature is complete in Christ (Colossians 2:9-10), transferred into God’s Kingdom (Colossians 1:13), seated with Christ in the place of authority (Ephesians 2:6), and a carrier of God’s presence (1 Corinthians 6:19). He is born of the incorruptible Word of God (1 Peter 1:23).\n\nPractical Example\nIf someone becomes a citizen of a new country, he must learn the rights, laws, and identity of that new citizenship. The new birth is far deeper. You have been transferred into God’s Kingdom. You must learn to live according to your new identity.\n\nConclusion\nYou are a new creature in Christ. Your past does not have final authority over you. Your salvation is by grace. You have received eternal life, righteousness, and fellowship with God. Now renew your mind with the Word and live according to your new life in Christ.","keyScriptures":"۲ قرنتیان ۵:۱۷-۱۸؛ یوحنا ۳:۱۶؛ رومیان ۱۰:۹-۱۱؛ افسسیان ۲:۸-۱۰؛ رومیان ۵:۱۷؛ اول یوحنا ۵:۱۱-۱۳؛ رومیان ۸:۱۶؛ اول تسالونیکیان ۵:۲۳؛ رومیان ۱۲:۲؛ کولسیان ۳:۱۰؛ اول پطرس ۲:۹؛ دوم پطرس ۱:۳؛ کولسیان ۱:۱۳؛ افسسیان ۲:۶؛ اول قرنتیان ۶:۱۹؛ اول پطرس ۱:۲۳","assignment":"Explain what “If anyone is in Christ, he is a new creature” means to you, using your own life as an example. Also explain why you can be assured of your salvation beyond feelings or circumstances.","audioFile":""},{"order":2,"code":"class_02_holy_spirit","classTitle":"Class 2: The Holy Spirit","title":"The Holy Spirit: God’s Presence, Power, and Fellowship in the Believer","text":"Lesson Objective\nThis lesson helps the student know the Holy Spirit as a divine Person, the active presence of God, and the essential power for Christian living. Without the Holy Spirit, Christianity becomes human effort. With Him, the believer receives power to live, pray, worship, serve, and witness.\n\n1. The Holy Spirit is not optional\nJesus told His disciples in Luke 24:49 to wait until they were endued with power from on high. In Acts 1:8 He said, “Ye shall receive power, after that the Holy Ghost is come upon you: and ye shall be witnesses unto me.” Christian life and service begin with the power of the Spirit, not human strength.\n\n2. Who is the Holy Spirit?\nThe Holy Spirit is not a feeling, energy, or religious atmosphere. He is God. Jesus called Him the Comforter and the Spirit of Truth in John 15:26. Genesis 1:2 shows the Spirit of God moving upon the face of the waters. He is the One who carries out the Father’s intentions and makes God’s presence real to us.\n\nThe Holy Spirit has personality. He speaks (Acts 13:2), can be grieved (Ephesians 4:30), teaches, guides, comforts, and strengthens. Therefore fellowship with Him is real relationship, not theory.\n\n3. The baptism and indwelling of the Holy Spirit\nAccording to 1 Corinthians 12:13, the Holy Spirit baptizes the believer into the Body of Christ at the new birth. The believer must also receive the Holy Spirit to live in him and function through him. This may happen at the same moment as salvation, but it must be understood and received by faith.\n\n4. The primary ministry of the Holy Spirit\nActs 1:8 shows that the Holy Spirit gives the believer dynamic ability to live the Christian life successfully and be an effective witness for Jesus. He is Comforter, Counselor, Helper, Intercessor, Advocate, Strengthener, and Standby.\n\n5. Receiving the Holy Spirit\nThe promise of the Spirit is for believers (Acts 2:17; Galatians 3:14). A believer can receive Him by faith, saying with reverence: “In the Name of Jesus Christ, I open my heart and receive the Holy Spirit.” Acts 19:6 also shows believers receiving the Holy Spirit through the laying on of hands.\n\n6. Speaking in tongues\nMark 16:17 identifies speaking in new tongues as a sign of believers. Jude 1:20 says we build ourselves up by praying in the Holy Spirit. 1 Corinthians 14:2 says the one who speaks in tongues speaks to God and speaks mysteries. Tongues help the believer pray beyond the limitation of natural language, glorify God, and edify himself.\n\n7. The sevenfold expression of the Spirit\nIsaiah 11:2 speaks of the Spirit of the Lord, wisdom, understanding, counsel, might, knowledge, and the fear of the Lord. This does not mean seven separate Spirits, but the many-sided fullness of the same Holy Spirit.\n\n8. Fruit and ministry gifts\nGalatians 5:22-23 lists the fruit expected in the life of the recreated human spirit: love, joy, peace, longsuffering, gentleness, goodness, faith, meekness, and temperance. Ephesians 4:11 also reveals ministry gifts given to equip the saints and build the Body of Christ.\n\nPractical Example\nA beautiful phone without power cannot function. A believer without active fellowship with the Holy Spirit may have information but lack power. The Holy Spirit is the divine power, guidance, and presence within you.\n\nConclusion\nThe Holy Spirit is essential. He lives in you, empowers you, builds you, guides you, and makes you an effective witness of Jesus. Fellowship with Him daily and pray in tongues consistently.","keyScriptures":"یوحنا ۱۴:۱۶-۲۰؛ اعمال ۱:۸؛ لوقا ۲۴:۴۹؛ اعمال ۲:۱-۴؛ اول قرنتیان ۱۲:۱۳؛ یوحنا ۱۵:۲۶؛ پیدایش ۱:۲؛ اشعیا ۶۳:۹-۱۰؛ افسسیان ۲:۲۲؛ یوحنا ۱۴:۱۷ و ۲۶؛ افسسیان ۴:۳۰؛ اعمال ۱۳:۲؛ یوحنا ۱۶:۸؛ یوئیل ۲:۲۸؛ اعمال ۲:۱۷؛ اعمال ۵:۳۲؛ غلاطیان ۳:۱۴؛ اعمال ۱۹:۶؛ مرقس ۱۶:۱۷؛ یهودا ۱:۲۰؛ اول قرنتیان ۱۴:۲ و ۱۵؛ اعمال ۱۰:۴۶؛ اشعیا ۱۱:۲؛ غلاطیان ۵:۲۲-۲۳؛ افسسیان ۴:۱۱-۱۲","assignment":"Pray in tongues for at least 10 minutes every day until the next lesson. Write down any changes, thoughts, strength, peace, or direction you notice.","audioFile":""},{"order":3,"code":"class_03_christian_doctrine","classTitle":"Class 3: Christian Doctrine","title":"Christian Doctrine: Foundations of Faith and Life in God’s Kingdom","text":"Lesson Objective\nThis lesson helps the student understand that Christian faith must be built on the Word of God and sound doctrine. Feelings, culture, personal experiences, and public opinion cannot replace Scripture.\n\n1. The supremacy of the Bible\nThe Bible contains the Word of God and is the final standard for Christian faith, conduct, service, and teaching. 2 Timothy 3:16-17 teaches that all Scripture is inspired by God and profitable for doctrine, reproof, correction, and instruction in righteousness. The Word communicates God’s will, thoughts, plans, and purposes.\n\n2. Living in two worlds\nColossians 1:13 says God has delivered us from the power of darkness and translated us into the Kingdom of His dear Son. The believer still lives in the physical world, but belongs to God’s Kingdom. John 18:36 shows that Christ’s Kingdom is not of this world. Romans 12:2 tells us not to conform to this world, but to be transformed by renewing the mind.\n\n3. What is doctrine?\nDoctrine is a recognizable set of beliefs, teachings, values, and instructions believed, taught, practiced, and lived by a people. Christian doctrine must come from the Scriptures, not from culture, assumptions, or human tradition. 1 Timothy 4:1 warns about false doctrines, so sound doctrine protects the believer.\n\n4. Righteousness and substitution\n2 Corinthians 5:21 says that Christ, who knew no sin, was made sin for us so that we might become the righteousness of God in Him. This reveals the doctrine of substitution. Jesus took our place. If He truly became sin for us, then we truly became righteous in Him. Romans 5:17 calls righteousness a gift.\n\n5. Repentance from dead works and faith toward God\nHebrews 6:1-2 lists foundational doctrines. Repentance from dead works means turning away from human efforts to earn acceptance with God. Hebrews 9:12-14 teaches that the blood of Christ purges our conscience from dead works to serve the living God. Faith toward God is the life of the Christian. Hebrews 11:1 says faith is the substance of things hoped for and the evidence of things not seen.\n\n6. Baptisms\nBaptism means immersion. The Holy Spirit baptizes the believer into the Body of Christ at the new birth. Water baptism is an outward sign of faith and identification with the death, burial, and resurrection of Christ (Romans 6:3-5; 1 Peter 3:21).\n\n7. Laying on of hands\nScripture shows laying on of hands for healing (Mark 16:18), ministering the Holy Spirit (Acts 19:6), impartation of spiritual gifts (1 Timothy 4:14), and ordination into ministry (Acts 13:1-3).\n\n8. Resurrection and eternal judgment\nChristianity teaches that death is not extinction. John 5:28-29 and 1 Thessalonians 4:13-17 speak of resurrection. Believers face the judgment seat of Christ for rewards, not condemnation. Unbelievers face the Great White Throne judgment (Revelation 20:11-15).\n\n9. Sanctification, holiness, and deliverance\nSanctification means being separated for God. 1 Corinthians 6:11 says believers are washed, sanctified, and justified. John 17:17 shows that the Word sanctifies. Holiness is connected to God’s presence in us, for the body is the temple of the Holy Spirit (1 Corinthians 6:19). Deliverance has already been accomplished in Christ. Colossians 1:13 says we have been delivered from the power of darkness.\n\nPractical Example\nA house built on sand falls in a storm, but a house built on rock stands. Sound doctrine is the rock foundation of the believer’s life.\n\nConclusion\nChristian doctrines are the pillars of faith. The Bible is the final authority. The believer has been made righteous, delivered, sanctified, called to live by faith, and established in God’s Kingdom.","keyScriptures":"دوم تیموتائوس ۳:۱۶-۱۷؛ کولسیان ۱:۱۳؛ یوحنا ۸:۲۳؛ یوحنا ۱۸:۳۶؛ رومیان ۱۲:۲؛ یوحنا ۱۵:۱۹؛ کولسیان ۳:۱-۲؛ عبرانیان ۱۲:۲۲؛ اول تیموتائوس ۴:۱؛ دوم قرنتیان ۵:۲۱؛ رومیان ۵:۱۷؛ عبرانیان ۶:۱-۲؛ عبرانیان ۹:۱۲-۱۴؛ عبرانیان ۱۱:۱-۶؛ رومیان ۱:۱۷؛ دوم قرنتیان ۵:۷؛ رومیان ۶:۳-۵؛ اول پطرس ۳:۲۱؛ مرقس ۱۶:۱۸؛ اعمال ۱۹:۶؛ اول تیموتائوس ۴:۱۴؛ اعمال ۱۳:۱-۳؛ یوحنا ۵:۲۸-۲۹؛ اول تسالونیکیان ۴:۱۳-۱۷؛ مکاشفه ۲۰:۱۱-۱۵؛ اول قرنتیان ۶:۱۱ و ۱۹؛ یوحنا ۱۷:۱۷؛ کولسیان ۱:۱۲-۱۳؛ کولسیان ۲:۱۵؛ فیلیپیان ۲:۹-۱۱","assignment":"Explain why sound doctrine is necessary for stability in the Christian life. Choose one doctrine from the lesson and write how you will apply it daily.","audioFile":""},{"order":4,"code":"class_04a_evangelism","classTitle":"Class 4A: Evangelism","title":"Evangelism: From Soul Saving to Discipleship","text":"Lesson Objective\nThis lesson teaches that evangelism is more than a short religious conversation. It is reaching people with the message that changed our lives, and then helping them become disciples of Christ.\n\n1. What is evangelism?\nEvangelism is sharing the good news of Jesus Christ with another person. It is the message of salvation, forgiveness, new life, and God’s Kingdom. Mark 16:15 commands believers to preach the Gospel to every creature. This responsibility belongs to all believers, not only to preachers.\n\n2. Soul saving and soul winning\nA person may hear the Gospel and pray, but if he is left alone without teaching, church connection, and follow-up, the work is incomplete. Matthew 28:19-20 commands us to go, teach, baptize, and disciple. True evangelism must lead to discipleship.\n\nA mother does not give birth to a baby and then abandon the child. The child must be fed, protected, and raised. In the same way, new believers must be followed up, taught the Word, and connected to the local church.\n\n3. God made us partners in saving others\n2 Corinthians 5:18-20 says God reconciled us to Himself and gave us the ministry of reconciliation. We are ambassadors for Christ. When we share the Gospel, we carry the message of God’s Kingdom.\n\n4. Why evangelize?\nWe evangelize because Jesus commanded it, because people must hear before they can believe (Romans 10:14-15), because the love of God is in us, and because the Gospel is the message of life. Evangelism also strengthens the believer, because faith becomes active when we testify.\n\n5. The Holy Spirit in evangelism\nActs 1:8 shows that the Holy Spirit empowers us to be witnesses. Evangelism is not done by human power alone. The Spirit gives boldness, wisdom, love, and the right words.\n\n6. Follow-up\nFollow-up means contacting the person, praying, sharing Scriptures, inviting him to church, answering questions, and helping him begin the Christian life. Evangelism without follow-up is like planting seed without watering it.\n\n7. Digital tools and records\nIt is wise to record the names of people we are praying for, those we have reached, and the status of follow-up. This helps us act responsibly and not forget new souls.\n\n8. Evangelism as a lifestyle\nEvangelism is not only a monthly program. It is a lifestyle. Opportunities exist in family, work, school, social media, and everyday relationships. We must speak with love, wisdom, and respect.\n\nPractical Example\nIf you found medicine that could save lives, love would not allow you to keep it to yourself. The Gospel is the message of life.\n\nConclusion\nEvangelism is sharing the message of life and continuing the work through follow-up and discipleship. Every Christian is responsible. We are ambassadors of reconciliation.","keyScriptures":"متی ۲۸:۱۹-۲۰؛ مرقس ۱۶:۱۵؛ دوم قرنتیان ۵:۱۷-۲۰؛ اعمال ۱:۸؛ یوحنا ۱۵:۱۶؛ رومیان ۱۰:۱۴-۱۵؛ اول قرنتیان ۹:۱۶؛ دانیال ۱۲:۳؛ امثال ۱۱:۳۰؛ لوقا ۱۵:۴-۷","assignment":"Write the names of people you want to pray for and share the Gospel with. Choose one person and describe a plan for prayer, contact, follow-up, and invitation to church fellowship.","audioFile":""},{"order":5,"code":"class_04b_cell_ministry","classTitle":"Class 4B: Cell Ministry","title":"Cell Ministry: Growth, Care, and Every Member’s Participation","text":"Lesson Objective\nThis lesson helps the student understand that cell ministry is not an optional extra program. It is a practical structure for growth, care, discipleship, evangelism, and every member’s participation in the Body of Christ.\n\n1. What is cell ministry?\nCell ministry is a smaller environment for fellowship, prayer, teaching, care, and growth. In the general church service, the whole congregation receives ministry. In the cell group, people have more opportunity to ask questions, serve, build relationships, and grow practically.\n\n2. Every member must grow and participate\nEphesians 4:11-16 shows that the saints are equipped so that every part supplies to the growth of the Body. 1 Corinthians 12 compares the Church to a human body. Every member has a function. No member is useless.\n\n3. Stability for new believers\nNew believers need care, prayer, answers, and encouragement. Acts 2:42-47 shows the early believers continuing in doctrine, fellowship, breaking of bread, and prayers. Growth happens in community.\n\n4. Cell ministry is not just a program\nCell ministry is how the Church grows through the growth and development of every member. Church growth is not only the increase of attendance; it is the maturity of people in Christ.\n\n5. Benefits for the student\nCell ministry helps the believer not to be isolated, to grow in the Word, to develop spiritual friendships, to receive encouragement, to participate in prayer, and to become active in service and evangelism. Hebrews 10:24-25 teaches us to stir one another to love and good works and not neglect gathering together.\n\n6. Your role in the cell\nA student should not only consume. He can pray, share a Scripture, invite someone, follow up a new believer, help with order, testify, and participate in outreach.\n\n7. Cell ministry and discipleship\n2 Timothy 2:2 shows the principle of transferring truth to faithful people who will teach others also. This is the spirit of discipleship.\n\n8. Cell ministry and evangelism\nA cell group is an outreach base. Members can pray for people, invite them, follow them up, and connect them to the Church and the Word.\n\nPractical Example\nA coal removed from the fire slowly grows cold. A believer separated from fellowship can weaken, but in the environment of prayer, Word, and love, faith grows stronger.\n\nConclusion\nCell ministry is a divine strategy for growth. Every believer should be planted, cared for, trained, and activated for service in the Body of Christ.","keyScriptures":"افسسیان ۴:۱۱-۱۶؛ اعمال ۲:۴۲-۴۷؛ اول قرنتیان ۱۲:۱۲-۲۷؛ عبرانیان ۱۰:۲۴-۲۵؛ متی ۲۸:۱۹-۲۰؛ دوم تیموتائوس ۲:۲؛ کولسیان ۲:۱۹؛ رومیان ۱۲:۴-۸","assignment":"Explain why participation in a cell group is important for your growth. Write how you can pray, serve, encourage others, and participate in evangelism through a cell group.","audioFile":""},{"order":6,"code":"class_05_character_prosperity","classTitle":"Class 5: Christian Character and Prosperity","title":"Christian Character and Prosperity: Growing from Glory to Glory","text":"Lesson Objective\nThis lesson teaches that the new creature must be seen in character, behavior, speech, relationships, decisions, and attitude toward prosperity. Salvation is instant, but Christian growth is progressive.\n\n1. Salvation is instant; growth is progressive\nWhen a person receives Jesus, he is saved immediately. But growth in character, discipline, love, patience, faithfulness, and maturity is progressive. 2 Corinthians 3:18 says we are changed from glory to glory as we behold the glory of the Lord.\n\n2. Christian character begins within\n1 Corinthians 6:17 says he that is joined to the Lord is one spirit. The believer has received divine life. This life must be expressed outwardly. Ephesians 5:18-21 teaches us to be filled with the Spirit so that His influence shapes our words, attitudes, and actions.\n\n3. The mirror of the Word\nThe Word of God is like a mirror. It reveals who we are in Christ and what we are becoming. The Word does not only expose faults; it shows the divine image into which we are being transformed.\n\n4. Fruit of the Spirit\nGalatians 5:22-23 lists love, joy, peace, longsuffering, gentleness, goodness, faith, meekness, and temperance. These qualities should be visible in family, church, work, and society.\n\n5. Guarding relationships\n1 Corinthians 15:33 says evil communications corrupt good manners. This is truth, not suggestion. Relationships influence thoughts, speech, decisions, and destiny. A believer must guard what he hears, watches, and receives.\n\n6. Kingdom prosperity\nProsperity is not merely money. 3 John 1:2 shows God’s desire for us to prosper and be in health as our soul prospers. True prosperity means living in God’s purpose, growing in character, giving, serving, and becoming a blessing.\n\n7. The seed of Abraham\nGalatians 3:29 says if we belong to Christ, we are Abraham’s seed and heirs according to the promise. God told Abraham, “I will bless you, and you shall be a blessing.” The believer is not only blessed; he is called to be a blessing.\n\n8. The principle of giving\nActs 20:35 says it is more blessed to give than to receive. Kingdom prosperity begins with giving. Giving includes money, time, love, service, prayer, attention, and resources. Giving frees the heart from selfishness.\n\n9. Character and prosperity belong together\nWithout character, prosperity can be dangerous. God wants us to grow in resources and also in wisdom, humility, faithfulness, and love. Character is the vessel that carries blessing.\n\nPractical Example\nA healthy tree is known by fruit, not only by leaves. A believer is known by the fruit of character, love, service, and blessing.\n\nConclusion\nThe new life must produce new character. Growth is progressive, the Word is our mirror, the Spirit forms God’s character in us, and true prosperity is living for God’s purpose and becoming a blessing.","keyScriptures":"اول قرنتیان ۶:۱۷؛ افسسیان ۵:۱۸-۲۱؛ دوم قرنتیان ۳:۱۸؛ غلاطیان ۵:۲۲-۲۳؛ اول قرنتیان ۱۵:۳۳؛ پیدایش ۱۲:۲-۳؛ غلاطیان ۳:۱۳-۱۴ و ۲۹؛ اعمال ۲۰:۳۵؛ دوم قرنتیان ۹:۶-۸؛ سوم یوحنا ۱:۲؛ رومیان ۱۲:۱-۲؛ متی ۵:۱۴-۱۶","assignment":"Write three areas of your character that need growth. For each one, write a practical decision. Also explain how you will grow in giving, serving, and being a blessing.","audioFile":""},{"order":7,"code":"class_06_local_assembly","classTitle":"Class 6: The Local Assembly","title":"The Local Assembly: Spiritual Family, Growth, and Responsible Membership","text":"Lesson Objective\nThis lesson teaches that the Church is not merely a building or religious meeting. It is the Body of Christ, the spiritual family, and God’s structure for growth, care, service, and mission on earth.\n\n1. The Universal Church\nThe Church refers to God’s called-out people. The Universal Church includes the entire Body of Christ on earth. Jesus said in Matthew 16:18, “I will build my church.” The Church is Christ’s work, not a human idea.\n\n2. The Local Assembly\nThe Universal Church is expressed in local assemblies around the world. A local church is a definite gathering of believers under leadership, teaching, fellowship, service, and shared mission. Every believer must be planted in a local church.\n\n3. Why church attendance is necessary\nMembership is not only a name on a list. It is commitment to fellowship, growth, service, and accountability. Hebrews 10:24-25 tells us not to forsake assembling together. There are blessings received in corporate worship, teaching, correction, prayer, and service that cannot be replaced by private devotion alone.\n\n4. The church nourishes and trains believers\nEphesians 4:11-16 shows that God placed ministry gifts in the Church to equip the saints and build the Body. Without a local church, a believer may lack consistent teaching, pastoral care, spiritual order, and opportunity to serve.\n\n5. Every member has a part\n1 Corinthians 12:12-18 shows the Body has many members, and every member is necessary. In the Church, each person can pray, encourage, serve, evangelize, give, help new believers, and participate in the mission.\n\n6. The first responsibility of a member\nThe first personal responsibility of a local assembly member is consistent attendance at corporate services. No one can attend, worship, receive teaching, and grow in fellowship on your behalf.\n\n7. The Church as the pillar of truth\n1 Timothy 3:15 calls the Church the house of God, the pillar and ground of truth. In a world of confusion, the Church preserves, proclaims, and transmits the truth of God’s Word.\n\n8. Official membership\nOfficial membership means commitment to a spiritual family, teaching, order, mission, and leadership. Completing Omidno7 Online School helps the student understand the foundations and responsibilities of membership.\n\nPractical Example\nA tree repeatedly moved from soil to soil does not take root or bear stable fruit. A believer who is not planted in a local church will lack stability. God wants us planted so we can flourish.\n\nConclusion\nThe local church is the believer’s spiritual family and place of growth. Every Christian should be planted, present, active, and responsible in a local assembly.","keyScriptures":"متی ۱۶:۱۸؛ افسسیان ۴:۱۱-۱۶؛ اول قرنتیان ۱۲:۱۲-۱۸؛ اعمال ۲:۴۲؛ عبرانیان ۱۰:۲۴-۲۵؛ مزامیر ۹۲:۱۳-۱۴؛ اول تیموتائوس ۳:۱۵؛ رومیان ۱۲:۴-۵؛ اول پطرس ۲:۵؛ متی ۵:۱۴-۱۶","assignment":"Explain why every believer needs a local church. Then write how you will become an active, faithful, and responsible member of Omidno7 Church.","audioFile":""},{"order":8,"code":"class_07_mobile_technology","classTitle":"Class 7: Mobile Technology","title":"Mobile Technology: A Tool for Growth, Evangelism, and Church Expansion","text":"Lesson Objective\nThis lesson teaches that technology is not only for entertainment, news, or convenience. It can be a powerful tool for personal growth, teaching, evangelism, follow-up, discipleship, and church growth.\n\n1. Technology and the Gospel\nMark 16:15 commands us to take the Gospel to all creation. Today, digital tools allow messages, videos, audios, Scriptures, meeting links, and teaching materials to reach many people quickly. This increases our opportunity and responsibility.\n\n2. Technology must serve God’s purpose\nTechnology is a tool, not the final purpose. A pen can be used to write truth or lies. A phone can be used to waste time or spread the Gospel. The believer must ask: Is my phone helping my spiritual growth and service, or only distracting me?\n\n3. Personal growth through digital tools\nA student can use a phone to read the Bible, listen to teachings, attend online meetings, take notes, review lessons, receive church announcements, and organize prayer and study. If a phone takes many hours each day, some of that time should be dedicated to the Word, prayer, and growth.\n\n4. Evangelism through mobile technology\nRomans 10:14-15 shows people must hear in order to believe. Today they may hear through a voice message, video, link, Scripture, personal testimony, or invitation to church. Digital evangelism should be personal, respectful, and followed up.\n\n5. Digital discipleship and follow-up\nMatthew 28:19-20 is a command to make disciples. Digital tools help us stay in touch with new believers, send Scriptures, introduce lessons, answer questions, invite them to online meetings, and monitor their growth.\n\n6. Discipline in technology use\nA good tool without discipline can become a distraction. The believer must manage social media, entertainment, and unprofitable content. Colossians 4:5-6 teaches wisdom in conduct and speech; this applies online as well.\n\n7. Technology for church participation\nA church app can unite announcements, online meetings, prayer links, online school, registration forms, notes, assignments, exams, and member follow-up. It helps members remain connected even when geographically distant.\n\n8. Responsibility\nWhen we have tools, we also have responsibility. If we can reach someone with the Gospel and do not, we miss an opportunity. If we can grow through digital resources but only waste time, we misuse the tool.\n\nPractical Example\nA knife in the hand of a surgeon can save life; in the wrong hand it can harm. Technology is the same. Its value depends on purpose and use.\n\nConclusion\nMobile technology can serve personal growth, teaching, evangelism, discipleship, and church growth. Your phone can be only entertainment, or it can become a tool for God’s Kingdom.","keyScriptures":"مرقس ۱۶:۱۵؛ متی ۲۸:۱۹-۲۰؛ اعمال ۱:۸؛ حبقوق ۲:۲؛ دانیال ۱۲:۴؛ رومیان ۱۰:۱۴-۱۵؛ دوم تیموتائوس ۲:۲؛ کولسیان ۴:۵-۶؛ اول قرنتیان ۹:۲۲-۲۳","assignment":"Explain how you can use your phone and digital tools for personal growth, teaching, evangelism, follow-up, and helping the church grow. Mention the tools or apps you want to use more consistently.","audioFile":""}],"hr":[{"order":1,"code":"class_01_new_creature","classTitle":"Lekcija 1: Novo stvorenje","title":"Novo stvorenje: novi identitet u Kristu","text":"Cilj lekcije\nOva lekcija poučava da primanje Isusa Krista nije samo moralno poboljšanje ili religijska odluka. To je novo rođenje i početak potpuno novog života. Izraz “novo stvorenje” dolazi iz 2. Korinćanima 5:17: “Ako je tko u Kristu, novo je stvorenje; staro prođe, gle, novo nasta.” Ova istina je temelj kršćanskog života.\n\n1. Što znači “novo stvorenje”?\nNovo stvorenje je osoba koja je ponovno rođena u Kristu. Ona nije stara osoba malo popravljena. U svom duhu primila je Božji život. Kada osoba primi Isusa Krista kao osobnog Gospodina i Spasitelja, ulazi u novu vrstu života. Prošlost više nije njezin identitet. Grijeh, strah, sram, osuda, neuspjeh i vlast tame više nemaju pravo definirati je.\n\nIvan 3:16 objavljuje da tko vjeruje u Isusa ne propadne, nego ima život vječni. To je više od obećanja neba; to je prijenos iz područja propasti u područje života. Kološanima 1:13 kaže da nas je Bog izbavio od vlasti tame i prenio u Kraljevstvo Sina svoje ljubavi. Zato vjernik ne smije sebe gledati kao žrtvu, poraženu osobu ili zarobljenika prošlosti.\n\n2. Tri velike stvari koje ste primili\nPrvo, primili ste vječni život. 1. Ivanova 5:11-12 kaže da nam je Bog dao vječni život, i taj je život u Njegovu Sinu. Vječni život nije samo beskonačno postojanje; to je kvaliteta Božjeg života dana ljudskom duhu.\n\nDrugo, primili ste pravednost. Rimljanima 5:18-19 pokazuje da smo kroz Kristovu poslušnost uvedeni u pravednost. Pravednost znači sposobnost stajati pred Bogom bez straha, krivnje, manje vrijednosti ili osude.\n\nTreće, primili ste zajedništvo s Bogom. 1. Ivanova 1:3 i Ivan 17:21 pokazuju da Božja svrha nije bila samo oprostiti grijeh, nego dovesti čovjeka u zajedništvo sa sobom. Sada možete poznavati Boga, živjeti s Njim, rasti u Njegovoj Riječi i biti vođeni Njegovim Duhom.\n\n3. Spasenje je po milosti, ne po djelima\nEfežanima 2:8-9 uči da ste spašeni milošću po vjeri, ne po djelima. Nijedan čovjek vas nije kvalificirao za spasenje i nijedan čovjek vas ne može diskvalificirati od onoga što vam je Bog dao u Kristu. Primili ste spasenje vjerom u srcu i priznanjem ustima, prema Rimljanima 10:9-10.\n\nDobra djela su važna, ali nisu korijen spasenja; ona su plod novog života. Ne činite dobra djela da biste postali spašeni. Budući da ste spašeni, dana vam je snaga da živite ispravno.\n\n4. Sigurnost spasenja ne temelji se na osjećajima\nVjernik ponekad može reći: “Danas se ne osjećam spašenim.” Osjećaji nisu mjerilo istine. Dva snažna svjedoka spasenja su Božja riječ i svjedočanstvo Duha Svetoga u našem srcu. Rimljanima 8:16 kaže da Duh svjedoči s našim duhom da smo djeca Božja. Kada se osjećaji mijenjaju, istina se ne mijenja.\n\n5. Čovjek je duh, ima dušu i živi u tijelu\n1. Solunjanima 5:23 pokazuje da je čovjek duh, duša i tijelo. Pri novom rođenju Božji život se prima u duh. Ali um se mora obnavljati Božjom riječju. Rimljanima 12:2 kaže da se preobražavamo obnovom uma. Ako je um još uvijek pun straha, srama i pogrešnog razmišljanja, vanjski život možda još ne odražava novu stvarnost. Riječ obnavlja um i mijenja život.\n\n6. Položaj novog stvorenja\nNovo stvorenje je potpuno u Kristu (Kološanima 2:9-10), preneseno u Božje Kraljevstvo (Kološanima 1:13), posjednuto s Kristom u mjestu autoriteta (Efežanima 2:6) i nositelj Božje prisutnosti (1. Korinćanima 6:19). Rođeno je od neraspadljive Božje riječi (1. Petrova 1:23).\n\nPraktičan primjer\nAko netko postane državljanin nove zemlje, mora naučiti prava, zakone i identitet tog novog državljanstva. Novo rođenje je mnogo dublje. Preneseni ste u Božje Kraljevstvo. Morate naučiti živjeti prema svom novom identitetu.\n\nZaključak\nVi ste novo stvorenje u Kristu. Vaša prošlost nema konačnu vlast nad vama. Vaše spasenje je po milosti. Primili ste vječni život, pravednost i zajedništvo s Bogom. Sada obnavljajte svoj um Riječju i živite prema novom životu u Kristu.","keyScriptures":"۲ قرنتیان ۵:۱۷-۱۸؛ یوحنا ۳:۱۶؛ رومیان ۱۰:۹-۱۱؛ افسسیان ۲:۸-۱۰؛ رومیان ۵:۱۷؛ اول یوحنا ۵:۱۱-۱۳؛ رومیان ۸:۱۶؛ اول تسالونیکیان ۵:۲۳؛ رومیان ۱۲:۲؛ کولسیان ۳:۱۰؛ اول پطرس ۲:۹؛ دوم پطرس ۱:۳؛ کولسیان ۱:۱۳؛ افسسیان ۲:۶؛ اول قرنتیان ۶:۱۹؛ اول پطرس ۱:۲۳","assignment":"Objasnite što “Ako je tko u Kristu, novo je stvorenje” znači za vas, koristeći vlastiti život kao primjer. Također objasnite zašto možete biti sigurni u svoje spasenje iznad osjećaja i okolnosti.","audioFile":""},{"order":2,"code":"class_02_holy_spirit","classTitle":"Lekcija 2: Duh Sveti","title":"Duh Sveti: Božja prisutnost, sila i zajedništvo u vjerniku","text":"Cilj lekcije\nOva lekcija pomaže polazniku upoznati Duha Svetoga kao božansku Osobu, aktivnu Božju prisutnost i nužnu silu za kršćanski život. Bez Duha Svetoga kršćanstvo postaje ljudski napor. S Njim vjernik prima snagu za život, molitvu, štovanje, služenje i svjedočenje.\n\n1. Duh Sveti nije opcija\nIsus je rekao učenicima u Luki 24:49 da čekaju dok ne budu obučeni u silu odozgor. U Djelima 1:8 rekao je: “Primit ćete snagu kad Duh Sveti siđe na vas i bit ćete mi svjedoci.” Kršćanski život i služba počinju silom Duha, a ne ljudskom snagom.\n\n2. Tko je Duh Sveti?\nDuh Sveti nije osjećaj, energija ili religiozna atmosfera. On je Bog. Isus ga je u Ivanu 15:26 nazvao Tješiteljem i Duhom istine. Postanak 1:2 pokazuje Duha Božjega kako se kreće nad vodama. On izvršava Očeve namjere i čini Božju prisutnost stvarnom za nas.\n\nDuh Sveti ima osobnost. On govori (Djela 13:2), može biti ožalošćen (Efežanima 4:30), poučava, vodi, tješi i jača. Zato je zajedništvo s Njim stvaran odnos, a ne teorija.\n\n3. Krštenje i prebivanje Duha Svetoga\nPrema 1. Korinćanima 12:13, Duh Sveti krsti vjernika u Tijelo Kristovo pri novom rođenju. Vjernik također treba primiti Duha Svetoga da živi u njemu i djeluje kroz njega. To se može dogoditi u istom trenutku kao spasenje, ali treba biti razumljeno i primljeno vjerom.\n\n4. Primarna služba Duha Svetoga\nDjela 1:8 pokazuje da Duh Sveti daje vjerniku dinamičnu sposobnost da uspješno živi kršćanski život i bude učinkovit svjedok za Isusa. On je Tješitelj, Savjetnik, Pomoćnik, Zagovornik, Branitelj, Onaj koji jača i Onaj koji stoji uz nas.\n\n5. Primanje Duha Svetoga\nObećanje Duha je za vjernike (Djela 2:17; Galaćanima 3:14). Vjernik ga može primiti vjerom, govoreći s poštovanjem: “U ime Isusa Krista otvaram svoje srce i primam Duha Svetoga.” Djela 19:6 također pokazuju primanje Duha Svetoga polaganjem ruku.\n\n6. Govorenje u jezicima\nMarko 16:17 navodi govor u novim jezicima kao znak vjernika. Juda 1:20 kaže da se izgrađujemo moleći u Duhu Svetom. 1. Korinćanima 14:2 kaže da onaj koji govori u jezicima govori Bogu i govori tajne. Jezici pomažu vjerniku moliti iznad ograničenja prirodnog jezika, slaviti Boga i izgrađivati sebe.\n\n7. Sedmerostruki izraz Duha\nIzaija 11:2 govori o Duhu Gospodnjem, mudrosti, razumijevanja, savjeta, sile, spoznaje i straha Gospodnjega. To ne znači sedam odvojenih duhova, nego mnogostruku puninu istog Duha Svetoga.\n\n8. Plod i službeni darovi\nGalaćanima 5:22-23 navodi plod koji se očekuje u životu obnovljenog ljudskog duha: ljubav, radost, mir, strpljivost, blagost, dobrota, vjera, krotkost i uzdržljivost. Efežanima 4:11 također otkriva službene darove dane za opremanje svetih i izgradnju Tijela Kristova.\n\nPraktičan primjer\nLijep telefon bez baterije ne može funkcionirati. Vjernik bez aktivnog zajedništva s Duhom Svetim može imati informacije, ali mu nedostaje sila. Duh Sveti je božanska snaga, vodstvo i prisutnost u vama.\n\nZaključak\nDuh Sveti je nužan. On živi u vama, osnažuje vas, izgrađuje, vodi i čini vas učinkovitim svjedokom Isusa. Svakodnevno imajte zajedništvo s Njim i ustrajno molite u jezicima.","keyScriptures":"یوحنا ۱۴:۱۶-۲۰؛ اعمال ۱:۸؛ لوقا ۲۴:۴۹؛ اعمال ۲:۱-۴؛ اول قرنتیان ۱۲:۱۳؛ یوحنا ۱۵:۲۶؛ پیدایش ۱:۲؛ اشعیا ۶۳:۹-۱۰؛ افسسیان ۲:۲۲؛ یوحنا ۱۴:۱۷ و ۲۶؛ افسسیان ۴:۳۰؛ اعمال ۱۳:۲؛ یوحنا ۱۶:۸؛ یوئیل ۲:۲۸؛ اعمال ۲:۱۷؛ اعمال ۵:۳۲؛ غلاطیان ۳:۱۴؛ اعمال ۱۹:۶؛ مرقس ۱۶:۱۷؛ یهودا ۱:۲۰؛ اول قرنتیان ۱۴:۲ و ۱۵؛ اعمال ۱۰:۴۶؛ اشعیا ۱۱:۲؛ غلاطیان ۵:۲۲-۲۳؛ افسسیان ۴:۱۱-۱۲","assignment":"Molite u jezicima najmanje 10 minuta svaki dan do sljedeće lekcije. Zapišite promjene, misli, snagu, mir ili vodstvo koje primijetite.","audioFile":""},{"order":3,"code":"class_03_christian_doctrine","classTitle":"Lekcija 3: Kršćanski nauk","title":"Kršćanski nauk: temelji vjere i života u Božjem Kraljevstvu","text":"Cilj lekcije\nOva lekcija pomaže polazniku razumjeti da kršćanska vjera mora biti izgrađena na Božjoj riječi i zdravom nauku. Osjećaji, kultura, osobna iskustva i javno mišljenje ne mogu zamijeniti Sveto pismo.\n\n1. Vrhovni autoritet Biblije\nBiblija sadrži Božju riječ i konačni je standard za kršćansku vjeru, ponašanje, službu i poučavanje. 2. Timoteju 3:16-17 uči da je sve Pismo od Boga nadahnuto i korisno za nauk, ukor, popravljanje i odgoj u pravednosti. Riječ objavljuje Božju volju, misli, planove i svrhe.\n\n2. Život u dva svijeta\nKološanima 1:13 kaže da nas je Bog izbavio od vlasti tame i prenio u Kraljevstvo Sina svoje ljubavi. Vjernik još živi u fizičkom svijetu, ali pripada Božjem Kraljevstvu. Ivan 18:36 pokazuje da Kristovo Kraljevstvo nije od ovoga svijeta. Rimljanima 12:2 govori nam da se ne suobličujemo ovome svijetu, nego da se preobražavamo obnovom uma.\n\n3. Što je nauk?\nNauk je prepoznatljiv skup vjerovanja, učenja, vrijednosti i uputa koje narod vjeruje, poučava, prakticira i živi. Kršćanski nauk mora dolaziti iz Svetog pisma, a ne iz kulture, pretpostavki ili ljudske tradicije. 1. Timoteju 4:1 upozorava na lažne nauke, zato zdrav nauk štiti vjernika.\n\n4. Pravednost i zamjena\n2. Korinćanima 5:21 kaže da je Krist, koji nije poznavao grijeha, učinjen grijehom za nas da bismo mi postali Božja pravednost u Njemu. To otkriva nauk zamjene. Isus je zauzeo naše mjesto. Ako je On zaista postao grijeh za nas, mi smo zaista postali pravedni u Njemu. Rimljanima 5:17 naziva pravednost darom.\n\n5. Pokajanje od mrtvih djela i vjera prema Bogu\nHebrejima 6:1-2 navodi temeljne nauke. Pokajanje od mrtvih djela znači okretanje od ljudskih pokušaja da zaradimo prihvaćanje kod Boga. Hebrejima 9:12-14 uči da Kristova krv čisti savjest od mrtvih djela kako bismo služili živome Bogu. Vjera prema Bogu je život kršćanina. Hebrejima 11:1 kaže da je vjera jamstvo onoga čemu se nadamo i dokaz onoga što ne vidimo.\n\n6. Krštenja\nKrštenje znači uranjanje. Duh Sveti krsti vjernika u Tijelo Kristovo pri novom rođenju. Krštenje u vodi je vanjski znak vjere i poistovjećenja s Kristovom smrću, ukopom i uskrsnućem (Rimljanima 6:3-5; 1. Petrova 3:21).\n\n7. Polaganje ruku\nPismo pokazuje polaganje ruku za ozdravljenje (Marko 16:18), služenje Duha Svetoga (Djela 19:6), darivanje duhovnih darova (1. Timoteju 4:14) i odvajanje za službu (Djela 13:1-3).\n\n8. Uskrsnuće i vječni sud\nKršćanstvo uči da smrt nije nestanak. Ivan 5:28-29 i 1. Solunjanima 4:13-17 govore o uskrsnuću. Vjernici će stati pred Kristovo sudište za nagrade, a ne za osudu. Nevjerujući će stati pred veliki bijeli prijestol (Otkrivenje 20:11-15).\n\n9. Posvećenje, svetost i oslobođenje\nPosvećenje znači biti odvojen za Boga. 1. Korinćanima 6:11 kaže da su vjernici oprani, posvećeni i opravdani. Ivan 17:17 pokazuje da Riječ posvećuje. Svetost je povezana s Božjom prisutnošću u nama jer je tijelo hram Duha Svetoga (1. Korinćanima 6:19). Oslobođenje je već ostvareno u Kristu. Kološanima 1:13 kaže da smo izbavljeni od vlasti tame.\n\nPraktičan primjer\nKuća izgrađena na pijesku pada u oluji, ali kuća izgrađena na stijeni ostaje. Zdrav nauk je stijena temelja vjernikova života.\n\nZaključak\nKršćanski nauci su stupovi vjere. Biblija je konačni autoritet. Vjernik je učinjen pravednim, oslobođen, posvećen, pozvan živjeti vjerom i uspostavljen u Božjem Kraljevstvu.","keyScriptures":"دوم تیموتائوس ۳:۱۶-۱۷؛ کولسیان ۱:۱۳؛ یوحنا ۸:۲۳؛ یوحنا ۱۸:۳۶؛ رومیان ۱۲:۲؛ یوحنا ۱۵:۱۹؛ کولسیان ۳:۱-۲؛ عبرانیان ۱۲:۲۲؛ اول تیموتائوس ۴:۱؛ دوم قرنتیان ۵:۲۱؛ رومیان ۵:۱۷؛ عبرانیان ۶:۱-۲؛ عبرانیان ۹:۱۲-۱۴؛ عبرانیان ۱۱:۱-۶؛ رومیان ۱:۱۷؛ دوم قرنتیان ۵:۷؛ رومیان ۶:۳-۵؛ اول پطرس ۳:۲۱؛ مرقس ۱۶:۱۸؛ اعمال ۱۹:۶؛ اول تیموتائوس ۴:۱۴؛ اعمال ۱۳:۱-۳؛ یوحنا ۵:۲۸-۲۹؛ اول تسالونیکیان ۴:۱۳-۱۷؛ مکاشفه ۲۰:۱۱-۱۵؛ اول قرنتیان ۶:۱۱ و ۱۹؛ یوحنا ۱۷:۱۷؛ کولسیان ۱:۱۲-۱۳؛ کولسیان ۲:۱۵؛ فیلیپیان ۲:۹-۱۱","assignment":"Objasnite zašto je zdrav nauk nužan za stabilnost u kršćanskom životu. Odaberite jedan nauk iz lekcije i napišite kako ćete ga svakodnevno primjenjivati.","audioFile":""},{"order":4,"code":"class_04a_evangelism","classTitle":"Lekcija 4A: Evangelizacija","title":"Evangelizacija: od spašavanja duša do učeništva","text":"Cilj lekcije\nOva lekcija poučava da evangelizacija nije samo kratak religijski razgovor. To je dosezanje ljudi porukom koja je promijenila naš život, a zatim pomaganje da postanu Kristovi učenici.\n\n1. Što je evangelizacija?\nEvangelizacija je dijeljenje dobre vijesti o Isusu Kristu s drugom osobom. To je poruka spasenja, oproštenja, novog života i Božjeg Kraljevstva. Marko 16:15 zapovijeda vjernicima da propovijedaju Evanđelje svakom stvorenju. Ova odgovornost pripada svim vjernicima, ne samo propovjednicima.\n\n2. Spašavanje duša i osvajanje duša\nOsoba može čuti Evanđelje i moliti, ali ako ostane bez pouke, povezanosti s crkvom i praćenja, djelo je nepotpuno. Matej 28:19-20 zapovijeda nam da idemo, poučavamo, krstimo i stvaramo učenike. Prava evangelizacija mora voditi u učeništvo.\n\nMajka ne rodi dijete i zatim ga napusti. Dijete se mora hraniti, štititi i odgajati. Na isti način, novi vjernici moraju biti praćeni, poučeni Riječi i povezani s lokalnom crkvom.\n\n3. Bog nas je učinio partnerima u spašavanju drugih\n2. Korinćanima 5:18-20 kaže da nas je Bog pomirio sa sobom i dao nam službu pomirenja. Mi smo Kristovi veleposlanici. Kada dijelimo Evanđelje, nosimo poruku Božjeg Kraljevstva.\n\n4. Zašto evangelizirati?\nEvangeliziramo jer je Isus zapovjedio, jer ljudi moraju čuti prije nego mogu vjerovati (Rimljanima 10:14-15), jer je Božja ljubav u nama i jer je Evanđelje poruka života. Evangelizacija također jača vjernika jer vjera postaje aktivna kada svjedočimo.\n\n5. Duh Sveti u evangelizaciji\nDjela 1:8 pokazuju da nas Duh Sveti osnažuje da budemo svjedoci. Evangelizacija se ne čini samo ljudskom snagom. Duh daje hrabrost, mudrost, ljubav i prave riječi.\n\n6. Praćenje\nPraćenje znači kontaktirati osobu, moliti, dijeliti stihove, pozvati je u crkvu, odgovoriti na pitanja i pomoći joj započeti kršćanski život. Evangelizacija bez praćenja je kao sadnja sjemena bez zalijevanja.\n\n7. Digitalni alati i evidencija\nMudro je bilježiti imena ljudi za koje molimo, one koje smo dosegli i stanje praćenja. To nam pomaže djelovati odgovorno i ne zaboraviti nove duše.\n\n8. Evangelizacija kao stil života\nEvangelizacija nije samo mjesečni program. Ona je stil života. Prilike postoje u obitelji, poslu, školi, društvenim mrežama i svakodnevnim odnosima. Moramo govoriti s ljubavlju, mudrošću i poštovanjem.\n\nPraktičan primjer\nAko biste pronašli lijek koji spašava živote, ljubav vam ne bi dopustila da ga zadržite samo za sebe. Evanđelje je poruka života.\n\nZaključak\nEvangelizacija je dijeljenje poruke života i nastavak djela kroz praćenje i učeništvo. Svaki kršćanin je odgovoran. Mi smo veleposlanici pomirenja.","keyScriptures":"متی ۲۸:۱۹-۲۰؛ مرقس ۱۶:۱۵؛ دوم قرنتیان ۵:۱۷-۲۰؛ اعمال ۱:۸؛ یوحنا ۱۵:۱۶؛ رومیان ۱۰:۱۴-۱۵؛ اول قرنتیان ۹:۱۶؛ دانیال ۱۲:۳؛ امثال ۱۱:۳۰؛ لوقا ۱۵:۴-۷","assignment":"Napišite imena ljudi za koje želite moliti i s kojima želite podijeliti Evanđelje. Odaberite jednu osobu i opišite plan molitve, kontakta, praćenja i poziva u crkveno zajedništvo.","audioFile":""},{"order":5,"code":"class_04b_cell_ministry","classTitle":"Lekcija 4B: Služba kućnih grupa","title":"Služba kućnih grupa: rast, briga i sudjelovanje svakog člana","text":"Cilj lekcije\nOva lekcija pomaže polazniku razumjeti da služba kućnih grupa nije neobavezan dodatni program. To je praktična struktura za rast, brigu, učeništvo, evangelizaciju i sudjelovanje svakog člana u Tijelu Kristovu.\n\n1. Što je služba kućnih grupa?\nSlužba kućnih grupa je manji prostor za zajedništvo, molitvu, pouku, brigu i rast. U općem crkvenom bogoslužju cijela zajednica prima služenje. U kućnoj grupi ljudi imaju više prilika postavljati pitanja, služiti, graditi odnose i praktično rasti.\n\n2. Svaki član mora rasti i sudjelovati\nEfežanima 4:11-16 pokazuje da se sveti opremaju kako bi svaki dio pridonosio rastu Tijela. 1. Korinćanima 12 uspoređuje Crkvu s ljudskim tijelom. Svaki član ima funkciju. Nijedan član nije beskoristan.\n\n3. Stabilnost za nove vjernike\nNovi vjernici trebaju brigu, molitvu, odgovore i ohrabrenje. Djela 2:42-47 pokazuju prve vjernike kako ustraju u nauku, zajedništvu, lomljenju kruha i molitvama. Rast se događa u zajednici.\n\n4. Služba kućnih grupa nije samo program\nSlužba kućnih grupa način je na koji Crkva raste kroz rast i razvoj svakog člana. Rast crkve nije samo povećanje posjećenosti; to je zrelost ljudi u Kristu.\n\n5. Koristi za polaznika\nKućna grupa pomaže vjerniku da ne bude izoliran, da raste u Riječi, razvija duhovna prijateljstva, prima ohrabrenje, sudjeluje u molitvi i postaje aktivan u službi i evangelizaciji. Hebrejima 10:24-25 uči nas poticati jedni druge na ljubav i dobra djela te ne zanemarivati okupljanje.\n\n6. Vaša uloga u grupi\nPolaznik ne bi trebao samo primati. Može moliti, podijeliti stih, pozvati nekoga, pratiti novog vjernika, pomoći u redu, svjedočiti i sudjelovati u dosezanju ljudi.\n\n7. Kućna grupa i učeništvo\n2. Timoteju 2:2 pokazuje načelo prenošenja istine vjernim ljudima koji će poučavati i druge. To je duh učeništva.\n\n8. Kućna grupa i evangelizacija\nKućna grupa je baza za dosezanje ljudi. Članovi mogu moliti za ljude, pozivati ih, pratiti ih i povezati ih s Crkvom i Riječju.\n\nPraktičan primjer\nUgljen izvađen iz vatre polako se hladi. Vjernik odvojen od zajedništva može oslabiti, ali u okruženju molitve, Riječi i ljubavi vjera jača.\n\nZaključak\nSlužba kućnih grupa je božanska strategija za rast. Svaki vjernik treba biti usađen, zbrinut, obučen i aktiviran za službu u Tijelu Kristovu.","keyScriptures":"افسسیان ۴:۱۱-۱۶؛ اعمال ۲:۴۲-۴۷؛ اول قرنتیان ۱۲:۱۲-۲۷؛ عبرانیان ۱۰:۲۴-۲۵؛ متی ۲۸:۱۹-۲۰؛ دوم تیموتائوس ۲:۲؛ کولسیان ۲:۱۹؛ رومیان ۱۲:۴-۸","assignment":"Objasnite zašto je sudjelovanje u kućnoj grupi važno za vaš rast. Napišite kako možete moliti, služiti, ohrabrivati druge i sudjelovati u evangelizaciji kroz kućnu grupu.","audioFile":""},{"order":6,"code":"class_05_character_prosperity","classTitle":"Lekcija 5: Kršćanski karakter i prosperitet","title":"Kršćanski karakter i prosperitet: rast iz slave u slavu","text":"Cilj lekcije\nOva lekcija poučava da se novo stvorenje mora vidjeti u karakteru, ponašanju, govoru, odnosima, odlukama i stavu prema prosperitetu. Spasenje je trenutačno, ali kršćanski rast je progresivan.\n\n1. Spasenje je trenutačno; rast je progresivan\nKada osoba primi Isusa, odmah je spašena. Ali rast u karakteru, disciplini, ljubavi, strpljivosti, vjernosti i zrelosti je progresivan. 2. Korinćanima 3:18 kaže da se mijenjamo iz slave u slavu dok promatramo Gospodinovu slavu.\n\n2. Kršćanski karakter počinje iznutra\n1. Korinćanima 6:17 kaže da je onaj koji se združi s Gospodinom jedan duh s Njim. Vjernik je primio božanski život. Taj život mora biti izražen izvana. Efežanima 5:18-21 poučava nas da budemo ispunjeni Duhom kako bi Njegov utjecaj oblikovao naše riječi, stavove i djela.\n\n3. Ogledalo Riječi\nBožja riječ je poput ogledala. Ona otkriva tko smo u Kristu i što postajemo. Riječ ne izlaže samo pogreške; ona pokazuje božansku sliku u koju se preobražavamo.\n\n4. Plod Duha\nGalaćanima 5:22-23 navodi ljubav, radost, mir, strpljivost, blagost, dobrotu, vjeru, krotkost i uzdržljivost. Te osobine trebaju biti vidljive u obitelji, crkvi, poslu i društvu.\n\n5. Čuvanje odnosa\n1. Korinćanima 15:33 kaže da loše društvo kvari dobre navike. To je istina, ne prijedlog. Odnosi utječu na misli, govor, odluke i sudbinu. Vjernik mora paziti što sluša, gleda i prima.\n\n6. Prosperitet Kraljevstva\nProsperitet nije samo novac. 3. Ivanova 1:2 pokazuje Božju želju da prosperiramo i budemo zdravi kao što prosperira naša duša. Pravi prosperitet znači živjeti u Božjoj svrsi, rasti u karakteru, davati, služiti i biti blagoslov.\n\n7. Abrahamovo sjeme\nGalaćanima 3:29 kaže da ako pripadamo Kristu, Abrahamovo smo sjeme i baštinici po obećanju. Bog je rekao Abrahamu: “Blagoslovit ću te i bit ćeš blagoslov.” Vjernik nije samo blagoslovljen; pozvan je biti blagoslov.\n\n8. Načelo davanja\nDjela 20:35 kaže da je blaženije davati nego primati. Prosperitet Kraljevstva počinje davanjem. Davanje uključuje novac, vrijeme, ljubav, služenje, molitvu, pažnju i resurse. Davanje oslobađa srce od sebičnosti.\n\n9. Karakter i prosperitet idu zajedno\nBez karaktera, prosperitet može biti opasan. Bog želi da rastemo u resursima, ali i u mudrosti, poniznosti, vjernosti i ljubavi. Karakter je posuda koja nosi blagoslov.\n\nPraktičan primjer\nZdravo stablo poznaje se po plodu, ne samo po lišću. Vjernik se poznaje po plodu karaktera, ljubavi, služenja i blagoslova.\n\nZaključak\nNovi život mora proizvesti novi karakter. Rast je progresivan, Riječ je naše ogledalo, Duh oblikuje Božji karakter u nama, a pravi prosperitet je življenje za Božju svrhu i postajanje blagoslovom.","keyScriptures":"اول قرنتیان ۶:۱۷؛ افسسیان ۵:۱۸-۲۱؛ دوم قرنتیان ۳:۱۸؛ غلاطیان ۵:۲۲-۲۳؛ اول قرنتیان ۱۵:۳۳؛ پیدایش ۱۲:۲-۳؛ غلاطیان ۳:۱۳-۱۴ و ۲۹؛ اعمال ۲۰:۳۵؛ دوم قرنتیان ۹:۶-۸؛ سوم یوحنا ۱:۲؛ رومیان ۱۲:۱-۲؛ متی ۵:۱۴-۱۶","assignment":"Napišite tri područja karaktera u kojima trebate rasti. Za svako napišite praktičnu odluku. Također objasnite kako ćete rasti u davanju, služenju i biti blagoslov.","audioFile":""},{"order":7,"code":"class_06_local_assembly","classTitle":"Lekcija 6: Lokalna crkva","title":"Lokalna crkva: duhovna obitelj, rast i odgovorno članstvo","text":"Cilj lekcije\nOva lekcija poučava da Crkva nije samo zgrada ili religijski sastanak. Ona je Tijelo Kristovo, duhovna obitelj i Božja struktura za rast, brigu, služenje i misiju na zemlji.\n\n1. Univerzalna Crkva\nCrkva označava Božji pozvani narod. Univerzalna Crkva uključuje cijelo Tijelo Kristovo na zemlji. Isus je rekao u Mateju 16:18: “Sagradit ću svoju Crkvu.” Crkva je Kristovo djelo, a ne ljudska ideja.\n\n2. Lokalna crkva\nUniverzalna Crkva izražava se u lokalnim crkvama širom svijeta. Lokalna crkva je određeno okupljanje vjernika pod vodstvom, poukom, zajedništvom, služenjem i zajedničkom misijom. Svaki vjernik treba biti usađen u lokalnu crkvu.\n\n3. Zašto je dolazak u crkvu potreban\nČlanstvo nije samo ime na popisu. To je predanost zajedništvu, rastu, služenju i odgovornosti. Hebrejima 10:24-25 govori nam da ne ostavljamo svoje zajedničko sastajanje. Postoje blagoslovi koje primamo u zajedničkom štovanju, pouci, ispravljanju, molitvi i služenju, a privatna pobožnost ih sama ne može zamijeniti.\n\n4. Crkva hrani i obučava vjernike\nEfežanima 4:11-16 pokazuje da je Bog postavio službene darove u Crkvi da opreme svete i izgrade Tijelo. Bez lokalne crkve vjerniku može nedostajati dosljedna pouka, pastirska briga, duhovni red i prilika za služenje.\n\n5. Svaki član ima dio\n1. Korinćanima 12:12-18 pokazuje da Tijelo ima mnogo članova i svaki je potreban. U Crkvi svaka osoba može moliti, ohrabriti, služiti, evangelizirati, davati, pomagati novim vjernicima i sudjelovati u misiji.\n\n6. Prva odgovornost člana\nPrva osobna odgovornost člana lokalne crkve je redovito sudjelovanje na zajedničkim službama. Nitko ne može umjesto vas doći, štovati, primiti pouku i rasti u zajedništvu.\n\n7. Crkva kao stup istine\n1. Timoteju 3:15 naziva Crkvu kućom Božjom, stupom i temeljem istine. U svijetu zbunjenosti Crkva čuva, objavljuje i prenosi istinu Božje riječi.\n\n8. Službeno članstvo\nSlužbeno članstvo znači predanost duhovnoj obitelji, pouci, redu, misiji i vodstvu. Završetak Online škole Omidno7 pomaže polazniku razumjeti temelje i odgovornosti članstva.\n\nPraktičan primjer\nStablo koje se stalno premješta iz zemlje u zemlju ne pušta korijen i ne donosi stabilan plod. Vjernik koji nije usađen u lokalnu crkvu nema stabilnost. Bog želi da budemo usađeni kako bismo cvjetali.\n\nZaključak\nLokalna crkva je duhovna obitelj i mjesto rasta vjernika. Svaki kršćanin treba biti usađen, prisutan, aktivan i odgovoran u lokalnoj crkvi.","keyScriptures":"متی ۱۶:۱۸؛ افسسیان ۴:۱۱-۱۶؛ اول قرنتیان ۱۲:۱۲-۱۸؛ اعمال ۲:۴۲؛ عبرانیان ۱۰:۲۴-۲۵؛ مزامیر ۹۲:۱۳-۱۴؛ اول تیموتائوس ۳:۱۵؛ رومیان ۱۲:۴-۵؛ اول پطرس ۲:۵؛ متی ۵:۱۴-۱۶","assignment":"Objasnite zašto svaki vjernik treba lokalnu crkvu. Zatim napišite kako ćete postati aktivan, vjeran i odgovoran član crkve Omidno7.","audioFile":""},{"order":8,"code":"class_07_mobile_technology","classTitle":"Lekcija 7: Mobilna tehnologija","title":"Mobilna tehnologija: alat za rast, evangelizaciju i rast crkve","text":"Cilj lekcije\nOva lekcija poučava da tehnologija nije samo za zabavu, vijesti ili praktičnost. Ona može biti snažan alat za osobni rast, poučavanje, evangelizaciju, praćenje, učeništvo i rast crkve.\n\n1. Tehnologija i Evanđelje\nMarko 16:15 zapovijeda nam da donesemo Evanđelje svakom stvorenju. Danas digitalni alati omogućuju da poruke, videozapisi, audiozapisi, stihovi, poveznice za sastanke i materijali za pouku brzo dođu do mnogih ljudi. To povećava našu priliku i odgovornost.\n\n2. Tehnologija mora služiti Božjoj svrsi\nTehnologija je alat, a ne konačna svrha. Olovka se može koristiti za pisanje istine ili laži. Telefon se može koristiti za gubljenje vremena ili za širenje Evanđelja. Vjernik se mora pitati: pomaže li moj telefon mom duhovnom rastu i službi ili me samo ometa?\n\n3. Osobni rast kroz digitalne alate\nPolaznik može koristiti telefon za čitanje Biblije, slušanje pouka, sudjelovanje na online sastancima, bilježenje, ponavljanje lekcija, primanje crkvenih obavijesti i organiziranje molitve i proučavanja. Ako telefon uzima mnogo sati dnevno, dio tog vremena treba posvetiti Riječi, molitvi i rastu.\n\n4. Evangelizacija kroz mobilnu tehnologiju\nRimljanima 10:14-15 pokazuje da ljudi moraju čuti da bi vjerovali. Danas mogu čuti kroz glasovnu poruku, video, poveznicu, stih, osobno svjedočanstvo ili poziv u crkvu. Digitalna evangelizacija treba biti osobna, puna poštovanja i praćena.\n\n5. Digitalno učeništvo i praćenje\nMatej 28:19-20 je zapovijed da stvaramo učenike. Digitalni alati pomažu nam ostati u kontaktu s novim vjernicima, slati stihove, predstaviti lekcije, odgovoriti na pitanja, pozvati ih na online sastanke i pratiti njihov rast.\n\n6. Disciplina u korištenju tehnologije\nDobar alat bez discipline može postati smetnja. Vjernik mora upravljati društvenim mrežama, zabavom i beskorisnim sadržajem. Kološanima 4:5-6 uči mudrosti u ponašanju i govoru; to vrijedi i online.\n\n7. Tehnologija za sudjelovanje u crkvi\nCrkvena aplikacija može ujediniti obavijesti, online sastanke, molitvene poveznice, online školu, obrasce za registraciju, bilješke, zadatke, ispite i praćenje članova. Pomaže članovima ostati povezani čak i kada su geografski udaljeni.\n\n8. Odgovornost\nKada imamo alate, imamo i odgovornost. Ako možemo nekoga dosegnuti Evanđeljem, a to ne učinimo, propuštamo priliku. Ako možemo rasti kroz digitalne resurse, a samo gubimo vrijeme, pogrešno koristimo alat.\n\nPraktičan primjer\nNož u ruci kirurga može spasiti život; u pogrešnoj ruci može ozlijediti. Tehnologija je ista. Njezina vrijednost ovisi o svrsi i uporabi.\n\nZaključak\nMobilna tehnologija može služiti osobnom rastu, poučavanju, evangelizaciji, učeništvu i rastu crkve. Vaš telefon može biti samo zabava ili alat za Božje Kraljevstvo.","keyScriptures":"مرقس ۱۶:۱۵؛ متی ۲۸:۱۹-۲۰؛ اعمال ۱:۸؛ حبقوق ۲:۲؛ دانیال ۱۲:۴؛ رومیان ۱۰:۱۴-۱۵؛ دوم تیموتائوس ۲:۲؛ کولسیان ۴:۵-۶؛ اول قرنتیان ۹:۲۲-۲۳","assignment":"Objasnite kako možete koristiti telefon i digitalne alate za osobni rast, poučavanje, evangelizaciju, praćenje i pomoć rastu crkve. Spomenite alate ili aplikacije koje želite koristiti dosljednije.","audioFile":""}]};
  const labels={
    fa:{review:'بررسی محتوای مدرسه',desc:'این بخش سبک شده است تا اپ هنگ نکند. هر درس جداگانه باز می‌شود.',fa:'فارسی',en:'انگلیسی',hr:'کرواتی',full:'نمایش متن کامل درس',hide:'بستن متن کامل',assignment:'تکلیف درس',refs:'آیات کلیدی',audio:'شنیدن فایل صوتی',speed:'سرعت پخش',noAudio:'فایل صوتی برای این زبان فعلاً موجود نیست.',open:'باز کردن',back:'بازگشت'},
    en:{review:'Review School Content',desc:'This section is now lightweight. Each lesson opens separately to prevent freezing.',fa:'Persian',en:'English',hr:'Croatian',full:'Show full lesson text',hide:'Hide full lesson text',assignment:'Assignment',refs:'Key Scriptures',audio:'Listen to audio lesson',speed:'Playback speed',noAudio:'Audio is not available for this language yet.',open:'Open',back:'Back'},
    hr:{review:'Pregled sadržaja škole',desc:'Ovaj je dio optimiziran. Svaka se lekcija otvara zasebno kako aplikacija ne bi zapela.',fa:'Perzijski',en:'Engleski',hr:'Hrvatski',full:'Prikaži cijeli tekst lekcije',hide:'Sakrij cijeli tekst lekcije',assignment:'Zadatak',refs:'Ključni stihovi',audio:'Preslušaj audio lekciju',speed:'Brzina reprodukcije',noAudio:'Audio lekcija za ovaj jezik još nije dostupna.',open:'Otvori',back:'Natrag'}
  };
  const bookNames={
    en:{'۲ قرنتیان':'2 Corinthians','دوم قرنتیان':'2 Corinthians','اول قرنتیان':'1 Corinthians','۱ قرنتیان':'1 Corinthians','یوحنا':'John','رومیان':'Romans','افسسیان':'Ephesians','اول یوحنا':'1 John','اول تسالونیکیان':'1 Thessalonians','کولسیان':'Colossians','اول پطرس':'1 Peter','دوم پطرس':'2 Peter','اعمال':'Acts','غلاطیان':'Galatians','قلاتیان':'Galatians','لوقا':'Luke','مرقس':'Mark','متی':'Matthew','اشعیا':'Isaiah','پیدایش':'Genesis'},
    hr:{'۲ قرنتیان':'2. Korinćanima','دوم قرنتیان':'2. Korinćanima','اول قرنتیان':'1. Korinćanima','۱ قرنتیان':'1. Korinćanima','یوحنا':'Ivan','رومیان':'Rimljanima','افسسیان':'Efežanima','اول یوحنا':'1. Ivanova','اول تسالونیکیان':'1. Solunjanima','کولسیان':'Kološanima','اول پطرس':'1. Petrova','دوم پطرس':'2. Petrova','اعمال':'Djela','غلاطیان':'Galaćanima','قلاتیان':'Galaćanima','لوقا':'Luka','مرقس':'Marko','متی':'Matej','اشعیا':'Izaija','پیدایش':'Postanak'}
  };
  function esc(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));}
  function nl(s){return String(s||'').split(/\n{2,}/).map(p=>'<p>'+esc(p).replace(/\n/g,'<br>')+'</p>').join('');}
  function lang(){const c=(document.documentElement.className+' '+document.body.className+' '+(localStorage.getItem('omideno7_lang')||'')).toLowerCase(); if(/\bhr\b|cro/.test(c))return 'hr'; if(/\ben\b|eng/.test(c))return 'en'; return 'fa';}
  function trRef(ref,L){ if(L==='fa') return ref; let out=String(ref||''); const map=bookNames[L]||{}; Object.keys(map).sort((a,b)=>b.length-a.length).forEach(k=>{out=out.replaceAll(k,map[k]);}); return out.replace(/[۰-۹]/g,d=>'۰۱۲۳۴۵۶۷۸۹'.indexOf(d)).replace(/[؛]/g,';').replace(/آیات/g,'').replace(/آیه/g,'').replace(/باب/g,''); }
  function refs(txt,L,code){return String(txt||'').split(/[؛;]+/).map(x=>x.trim()).filter(Boolean).slice(0,18).map((r,i)=>{const rr=trRef(r,L); return `<button type="button" class="school-btn light v6314-review-ref" data-review-ref="${esc(rr)}" data-raw-ref="${esc(r)}">${esc(rr)}</button>`;}).join('');}
  function audioHtml(lesson,L){
    if(L!=='fa') return `<p class="school-muted">${esc(labels[L].noAudio)}</p>`;
    const file=(lesson.audioFile||`class-${String(lesson.order).padStart(2,'0')}-fa.mp3`).replace(/^school-audio\//,'');
    const url=`${SUPABASE_URL}/storage/v1/object/public/school-audio/${encodeURIComponent(file)}`;
    const id='safeAudio_'+lesson.code;
    return `<div class="school-audio-box"><h4>${esc(labels[L].audio)}</h4><audio id="${esc(id)}" controls preload="none" src="${esc(url)}" style="width:100%"></audio><label class="school-muted" style="display:block;margin-top:8px">${esc(labels[L].speed)} <select data-v6315-speed="${esc(id)}"><option value="0.75">0.75x</option><option value="1" selected>1x</option><option value="1.25">1.25x</option><option value="1.5">1.5x</option><option value="2">2x</option></select></label></div>`;
  }
  function lessonCard(lesson,L){
    return `<div class="school-card v6315-lesson-card" data-safe-lesson="${esc(lesson.code)}"><h3>${esc(lesson.classTitle)}</h3><h4>${esc(lesson.title)}</h4>${audioHtml(lesson,L)}<div class="v6314-review-card"><p><strong>${esc(labels[L].refs)}:</strong></p><div class="v6314-ref-list">${refs(lesson.keyScriptures,L,lesson.code)}</div><div class="v6314-ref-output" hidden></div></div><div class="school-card soft"><strong>${esc(labels[L].assignment)}:</strong><p>${esc(lesson.assignment)}</p></div><button type="button" class="school-btn gold" data-toggle-full="${esc(lesson.code)}">${esc(labels[L].full)}</button><div class="v6315-full-text" id="full_${esc(lesson.code)}" hidden></div></div>`;
  }
  function render(L){
    const area=document.getElementById('adminSchoolArea')||document.getElementById('adminMainArea')||document.querySelector('#schoolContent,#schoolPage,#school');
    if(!area)return;
    const A=labels[L];
    area.innerHTML=`<div class="school-card v6315-safe-review"><h2>${esc(A.review)}</h2><p class="school-muted">${esc(A.desc)}</p><div class="school-tabs"><button class="school-tab ${L==='fa'?'active':''}" data-safe-lang="fa">${esc(A.fa)}</button><button class="school-tab ${L==='en'?'active':''}" data-safe-lang="en">${esc(A.en)}</button><button class="school-tab ${L==='hr'?'active':''}" data-safe-lang="hr">${esc(A.hr)}</button></div></div><div class="v6315-lessons">${(LESSONS[L]||LESSONS.fa).map(x=>lessonCard(x,L)).join('')}</div>`;
    bind(area,L);
  }
  function bind(root,L){
    root.querySelectorAll('[data-safe-lang]').forEach(b=>b.onclick=()=>render(b.dataset.safeLang));
    root.querySelectorAll('[data-toggle-full]').forEach(b=>b.onclick=()=>{
      const code=b.dataset.toggleFull; const box=document.getElementById('full_'+code); const lesson=(LESSONS[L]||[]).find(x=>x.code===code); if(!box||!lesson)return;
      if(box.hidden){ box.innerHTML=`<div class="school-card"><h3>${esc(lesson.title)}</h3>${nl(lesson.text)}</div>`; box.hidden=false; b.textContent=labels[L].hide; }
      else { box.hidden=true; box.innerHTML=''; b.textContent=labels[L].full; }
    });
    root.querySelectorAll('[data-v6315-speed]').forEach(sel=>sel.onchange=()=>{const a=document.getElementById(sel.dataset.v6315Speed); if(a)a.playbackRate=parseFloat(sel.value||'1');});
  }
  function install(){
    const st=document.getElementById('v6315-style')||document.createElement('style'); st.id='v6315-style'; st.textContent=`
      .bottom-nav{min-height:88px!important;padding-bottom:calc(18px + env(safe-area-inset-bottom,0px))!important;overflow:visible!important}.bottom-nav .nav-inner{grid-template-columns:repeat(6,minmax(42px,1fr))!important;max-width:1000px!important}.bottom-nav .nav-btn{min-width:0!important;padding:7px 2px!important}.bottom-nav .nav-btn span:last-child{font-size:clamp(.52rem,1.35vw,.72rem)!important;white-space:nowrap!important}main{padding-bottom:120px!important}@media(min-width:760px){.bottom-nav .nav-inner{max-width:980px!important}.bottom-nav .nav-btn span:last-child{font-size:.76rem!important}}#adminMainArea,#adminSchoolArea{max-width:100%;overflow-x:hidden}.school-admin-table{display:block;max-width:100%;overflow-x:auto}.v6315-full-text{max-height:58vh;overflow:auto;margin-top:12px}.v6315-lessons{display:grid;gap:14px}.v6314-ref-list{display:flex;flex-wrap:wrap;gap:8px}.v6314-review-ref{white-space:normal!important;text-align:start!important}`; if(!st.parentNode)document.head.appendChild(st);
  }
  document.addEventListener('click',function(e){const b=e.target.closest&&e.target.closest('#loadSchoolContentReview'); if(!b)return; e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation(); install(); render(lang());},true);
  document.addEventListener('DOMContentLoaded',install); setTimeout(install,300);
  window.OMIDNO7_V6315='loaded';
})();
